-- Migration 012h: Implementation Plans — Batch H (IDs 104-123 selected)
-- ─────────────────────────────────────────────────────────────────────────────────────
-- Health systems strengthening, NHI, PEPFAR transition, TB, PHC, mental health,
-- tobacco control, provincial turnarounds, private health market reforms;
-- SMME finance, procurement set-asides, SEFA, SEDA, cannabis licensing,
-- informal economy formalisation, ESD, and JET-SMME finance.
-- ─────────────────────────────────────────────────────────────────────────────────────

BEGIN;

-- ── ID 104: NHI Phased Implementation: Credible Roadmap and Costed Financing Plan ────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    104,
    'The NHI Act (Act 20 of 2023) establishes the NHI Fund as a single purchaser of health services but faces constitutional challenges from medical schemes, the DA, and the Board of Healthcare Funders. A credible phased implementation strategy suspends the most contested provisions while building the institutional and fiscal foundations. Phase 1 (2024–2028) focuses on District Health System (DHS) strengthening, essential medicines supply chain reform, health facility accreditation, and the digital health infrastructure (HPRS patient records, interoperable claims systems) required for Fund operations. Phase 2 (2029–2034) activates mandatory NHI Fund purchasing for primary and district hospital care, with medical schemes permitted to cover co-payments and complementary benefits. Phase 3 (2034+) extends to specialist and central hospital services. Presidential Health Compact workstreams developed by the DoH technical team estimate full implementation cost at R400–850 billion/year, requiring a dedicated health payroll tax, VAT reallocation, and medical scheme credit reform. National Treasury''s medium-term costing must be completed and published before the Fund commences contracting.',
    '[
      {"step":1,"title":"Costing and Financing Plan","description":"Commission and publish a full actuarial costing of NHI — disaggregated by service package, phase, and population — through a joint DoH/National Treasury/NHLS technical team; engage the Health Economics Unit (UCT) and HSRC for independent peer review; present to Cabinet and Parliament by end-2025","timeline":"2024–2025","responsible_party":"DoH / National Treasury / Health Economics Unit UCT"},
      {"step":2,"title":"Phase 1 DHS Strengthening","description":"Implement the District Health System investment package: (a) complete health facility condition assessments in all 52 districts; (b) fund 5,000 infrastructure backlogs through the Health Facility Revitalisation Grant; (c) deploy HPRS digital patient records to 500 priority clinics; (d) establish the Office of Health Standards Compliance inspection programme covering all public facilities by 2027","timeline":"2025–2028","responsible_party":"DoH / Provincial Health Departments / OHSC"},
      {"step":3,"title":"NHI Fund Governance Establishment","description":"Establish the NHI Fund board with credible governance: independent non-executive directors with actuarial, public health, and audit credentials; CMS technical support for benefit design; Treasury concurrence on investment policy; and a dedicated NHI Procurement Office within the Fund with ring-fenced budget","timeline":"2025–2026","responsible_party":"DoH / National Treasury / CMS"},
      {"step":4,"title":"Provider Accreditation System","description":"Build the provider accreditation database under OHSC: accreditation standards for GPs, community health centres, and district hospitals; certification of private providers willing to contract with the Fund; and a tariff-setting methodology based on the Reference Price List, updated annually","timeline":"2026–2028","responsible_party":"OHSC / DoH / CMS"},
      {"step":5,"title":"Medical Schemes Transition Framework","description":"Publish the Medical Schemes Act amendment bill: (a) redefine Prescribed Minimum Benefits for co-payment complementary cover; (b) establish risk equalisation between open and restricted schemes; (c) create a transition timeline for medical scheme members phased into NHI purchasing from 2029","timeline":"2026–2028","responsible_party":"DoH / CMS / National Treasury"},
      {"step":6,"title":"Phase 2 Activation: PHC and District Purchasing","description":"Activate NHI Fund purchasing for primary and district hospital services from 2029: publish contracting frameworks for GPs (capitation model), community health centres (global budget), and district hospitals; integrate the PEPFAR-domesticated HIV/AIDS programme into NHI benefit packages","timeline":"2029–2034","responsible_party":"NHI Fund / DoH / Provincial Health Departments"},
      {"step":7,"title":"Phase 3 Specialist Services and Fiscal Review","description":"Commission a mid-term actuarial review of Phase 2 outcomes; submit Phase 3 activation proposal to Parliament; extend NHI purchasing to specialist outpatient and central hospital services contingent on health infrastructure quality and Fund financial sustainability","timeline":"2034+","responsible_party":"NHI Fund / DoH / National Treasury / Parliament"}
    ]',
    'Phase 1 (2024–2028): DHS strengthening and Fund establishment; Phase 2 (2029–2034): PHC and district hospital purchasing; Phase 3 (2034+): full specialist coverage. Constitutional litigation may extend Phase 1 by 2–3 years.',
    'Phase 1 investment: R30–50 billion (facility revitalisation, HPRS, OHSC expansion) over MTEF; full NHI Fund: R400–850 billion/year at peak implementation requiring new dedicated health levy of 2–4% payroll tax plus reallocation of medical scheme tax credits (currently R25 billion/year).',
    'NHI Act 20 of 2023 is in force but subject to constitutional challenge. Medical Schemes Act 131 of 1998 amendment required for Phase 2 transition. Health Professions Act 56 of 1974 and Pharmacy Act 53 of 1974 amendments needed for scope-of-practice adjustments. Public Finance Management Act compliance required for Fund governance.',
    'The NHI Fund is established by promulgation of Act 20 of 2023; the DoH Minister may phase implementation through regulations under section 57. Medical Schemes Act amendment requires ordinary legislation through Parliament. The payroll tax requires a dedicated NHI levy bill introduced by National Treasury. PFMA Schedule 3A public entity status requires Treasury concurrence.',
    'NHI is ANC policy and has broad intra-party support, though fiscal conservatives in the GNU (DA, ActionSA) oppose the single-payer model. The Constitutional Court challenge by the BHF and DA will determine whether the Fund can proceed as designed. Labour (COSATU, NEHAWU) strongly support. The private health industry (Discovery, Mediclinic, Netcare) has litigated and lobbied but may accept a complementary benefits model. A phased approach with a credible financing plan is the most viable political pathway.',
    'Taiwan''s single-payer NHI (1995) is the most directly relevant precedent — successfully absorbed multiple insurance schemes. Thailand''s Universal Coverage Scheme (2002) achieved near-universal coverage at 4% of GDP using capitation for PHC. Rwanda''s Mutuelle de Santé community health insurance scheme is the leading African model. UK NHS provides the template for a public integrated system. All emphasise strong primary care foundations before specialist purchasing.'
);

-- ── ID 105: PEPFAR Funding Transition: Domestic HIV/AIDS Programme Financing ─────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    105,
    'PEPFAR provides approximately $500 million (R9 billion) per year to South Africa''s HIV/AIDS response, supporting 5.5 million people on antiretroviral therapy, VMMC scale-up, PMTCT, and the bulk of the treatment cascade clinical infrastructure operated by NGOs (Right to Care, Anova Health). The 2025 PEPFAR review under the US administration has introduced genuine uncertainty about programme continuity. National Treasury estimates R15 billion is needed to fully domesticate all PEPFAR-funded programmes. The Conditional Grant system — specifically the HIV, TB, Malaria and Community Outreach Grant and the National Tertiary Services Grant — are the primary domestic financing vehicles. A credible domestication plan must sequence transitions by risk: ARV supply is non-negotiable, VMMC and PMTCT are high priority, and NGO service delivery platforms must either be absorbed into the public system or funded through DoH contracts. The NHI Fund, when operational, would absorb these as NHI benefit packages.',
    '[
      {"step":1,"title":"PEPFAR Programme Audit and Risk Stratification","description":"Commission a comprehensive audit of all PEPFAR-funded activities in SA: (a) catalogue all implementing partners (IPs), service volumes, beneficiary numbers, and annual costs; (b) stratify by risk of service disruption if funding lapses — ARV supply chain (critical), PMTCT (critical), VMMC (high), laboratory services (high), NGO-managed ART sites (medium); (c) submit risk report to Cabinet by Q2 2025","timeline":"Q1–Q2 2025","responsible_party":"DoH / SANAC / USAID SA"},
      {"step":2,"title":"Emergency ARV Buffer Stock and Supply Chain","description":"Increase national ARV buffer stock from 3 months to 9 months using a combination of SANAC Trust procurement, NDOH central procurement, and the NHLS distribution network; negotiate multi-year supply agreements with generic ARV manufacturers (Aspen Pharmacare, Cipla Quality Chemical) to reduce unit costs by 20–30%","timeline":"Q2 2025–Q4 2025","responsible_party":"DoH / SANAC / NHLS / National Treasury"},
      {"step":3,"title":"Conditional Grant Recapitalisation","description":"Restructure the HIV, TB, Malaria and Community Outreach Grant: (a) increase baseline allocation by R8–10 billion over MTEF to cover ARV, PMTCT, VMMC, and laboratory costs currently funded by PEPFAR; (b) introduce a ring-fenced PEPFAR Transition Sub-Grant with dedicated monitoring; (c) DoH publish quarterly implementation reports to Parliament","timeline":"2025 MTBPS and 2026 Budget","responsible_party":"National Treasury / DoH"},
      {"step":4,"title":"NGO Platform Transition","description":"Transition the top 20 PEPFAR-funded NGO implementing partners to DoH service level agreements funded through the public health grants system: (a) establish a standardised DoH NGO contracting framework with performance benchmarks; (b) absorb critical NGO clinical staff into community health worker and PHC posts under the CHW employment programme; (c) Right to Care, Anova Health, and similar IPs must transition from USAID SAs to DoH SAs by end-2026","timeline":"2025–2026","responsible_party":"DoH / Provincial Health Departments / SANAC"},
      {"step":5,"title":"SANAC Governance and Domestic Funding","description":"Strengthen the South African National AIDS Council as the domestic coordination body: (a) increase SANAC Trust domestic funding from R500 million to R2 billion/year through a dedicated line item; (b) appoint a permanent CEO with public health and fiscal management credentials; (c) consolidate all HIV/TB programme data reporting under DHIS2 platform managed by DoH","timeline":"2025–2026","responsible_party":"SANAC / DoH / Presidency"},
      {"step":6,"title":"Long-Term NHI Integration","description":"Design the HIV/AIDS comprehensive care package as a core NHI benefit package: ARVs as a zero-co-payment medicine through the NHI Essential Medicines formulary; integrate PEPFAR-funded testing, counselling, and ART initiation into the NHI primary care capitation package; submit benefit package design to the NHI Fund board for approval","timeline":"2027–2030","responsible_party":"NHI Fund / DoH / CMS"}
    ]',
    'Emergency measures and ARV buffer stock: Q2–Q4 2025. Conditional grant recapitalisation: 2025 MTBPS and 2026 Budget. NGO transition to DoH contracts: 2025–2026. Full domestic financing: 2027–2028. NHI integration: 2029–2030.',
    'R15 billion/year additional domestic funding required at full domestication (above current baseline of R22 billion HIV/TB conditional grant). Phase 1 emergency buffer: R3 billion from contingency reserve. MTEF increase: R8–10 billion over 3 years. NHI integration reduces incremental costs through pooled purchasing.',
    'No new primary legislation required for conditional grant restructuring. Public Finance Management Act (PFMA) and Division of Revenue Act (DoRA) govern grant mechanisms. SANAC Trust incorporated under the Companies Act and NPO Act — governance strengthening through board resolution. NHI benefit package integration requires NHI Act section 26 regulations.',
    'The Minister of Finance may increase conditional grant allocations through the MTBPS adjusted estimates and MTEF. DoRA is amended annually; PEPFAR transition funding requires an explicit ring-fenced sub-grant in the 2026 DoRA schedule. SANAC Trust governance requires Presidency and DoH action, not legislation.',
    'HIV/AIDS domestication has strong political support across the GNU — no party will oppose ARV continuity. The R15 billion fiscal ask is politically difficult in a consolidation environment; phasing and ring-fencing are essential for National Treasury acceptance. COSATU and health civil society (TAC, SECTION27) will mobilise strongly if ARV access is threatened, creating political pressure for prioritisation.',
    'Botswana domesticated PEPFAR-funded programmes over 2010–2018 using government ARV procurement, achieving 95% coverage with domestic funding — the most directly comparable African precedent. Uganda and Kenya have similar domestication programmes underway. The Global Fund''s co-financing model (requiring domestic expenditure to unlock grants) provides the incentive architecture SA should adopt for all HIV/TB funding streams.'
);

-- ── ID 106: Healthcare Worker Employment: Absorbing the Qualified but Unemployed ─────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    106,
    'South Africa produces approximately 5,000 medical graduates, 14,000 nursing graduates, and 3,000 allied health professionals annually from its universities and nursing colleges. An estimated 10,000 qualified healthcare workers cannot find employment in the public health system because provincial health departments have frozen posts due to compensation-of-employees budget ceilings. This is a compound crisis: public facilities are understaffed, patients wait months for appointments, and newly qualified professionals emigrate to the UK, Australia, and Canada. The solution is a conditional employment grant — ring-fenced outside the provincial compensation-of-employees baseline — that funds 8,000 new Community Health Worker (CHW) posts at a professional salary (not a stipend) and 2,000 professional nurse posts in district and regional hospitals, linked to provincial performance on healthcare output indicators.',
    '[
      {"step":1,"title":"Post Vacancy and Demand Assessment","description":"Commission the DoH National Health Workforce Planning Directorate to produce a province-by-province vacant post analysis: (a) map all funded-but-vacant posts in provincial health departments; (b) identify the 50 priority facilities with critical staff shortages; (c) crossmatch with HWSETA and SAQA databases of unemployed registered health professionals","timeline":"Q1–Q2 2026","responsible_party":"DoH / HWSETA / SAQA / Provincial Health Departments"},
      {"step":2,"title":"Conditional Healthcare Worker Employment Grant","description":"Design and gazette a dedicated Healthcare Worker Employment Conditional Grant under the DoRA: (a) R8 billion/year for 10,000 new posts (8,000 CHWs at R180,000/year CTC, 2,000 professional nurses at R320,000/year CTC plus benefits); (b) grant conditions link disbursements to provincial HR management scores and patient output metrics; (c) posts fall outside provincial compensation baselines but are funded for 5 years with a ratchet mechanism to incorporate into baselines","timeline":"2025 MTBPS design, 2026 Budget implementation","responsible_party":"National Treasury / DoH"},
      {"step":3,"title":"Community Health Worker Professionalisation","description":"Gazette the CHW Scope of Practice under the Health Professions Act: (a) formalise CHW as a regulated health professional category under HPCSA; (b) develop a nationally standardised CHW training curriculum (minimum 1-year certificate via HWSETA-accredited providers); (c) implement HPRS digital patient tracking tools on mobile devices for CHWs in Ward-Based Outreach Teams","timeline":"2025–2026","responsible_party":"DoH / HPCSA / HWSETA / SETA system"},
      {"step":4,"title":"Recruitment and Placement System","description":"Establish a National Health Workforce Recruitment Portal: (a) centrally-managed database of qualified unemployed health professionals; (b) automated matching with provincial post availability; (c) recruitment pipeline for CHW posts prioritising youth (18–35) in target communities; (d) public announcement of 10,000 posts with application portal by Q3 2026","timeline":"Q2–Q4 2026","responsible_party":"DoH / DPSA / HWSETA"},
      {"step":5,"title":"Provincial Performance Accountability","description":"Link grant disbursements to provincial quarterly scorecards: (a) targets include average time-to-appointment at PHC level, antiretroviral initiation rates, maternal mortality, and immunisation coverage; (b) provinces with two consecutive quarters of under-performance face grant suspension with DoH support intervention; (c) annual parliamentary report on CHW employment outcomes","timeline":"Ongoing from 2026","responsible_party":"DoH / National Treasury / OGAC"},
      {"step":6,"title":"Emigration Retention Incentives","description":"Introduce targeted rural and peri-urban retention packages: (a) student loan forgiveness after 5 years of public service in underserved areas; (b) accelerated specialist training access for public-sector physicians; (c) bilateral engagement with UK NHS and Australian AHPRA to establish managed migration frameworks that return professionals after fixed-term contracts","timeline":"2026–2027","responsible_party":"DoH / DHET / NSFAS / DIRCO"}
    ]',
    'Grant design: 2025 MTBPS. First 5,000 posts filled: Q3 2026. Full 10,000 posts: Q1 2027. CHW professionalisation regulations: 2026. Provincial accountability framework: operational from 2026.',
    'R8 billion/year for 10,000 posts at full implementation. HPRS digital tools for CHWs: R500 million capital (World Bank Health Systems Strengthening Project co-financing available). Student loan forgiveness: R200 million/year from NSFAS. Total additional fiscal cost: R8.7 billion/year above current baselines.',
    'No new primary legislation for grant structure — DoRA amendment sufficient. CHW scope-of-practice regulations under Health Professions Act 56 of 1974 (Section 47) require Ministerial gazette. HPCSA registration category for CHWs may require amendment to the Allied Health Professions Act 63 of 1982. Employment conditions under BCEA and PSAP must be applied to CHW posts.',
    'DoRA grant schedule amended annually by Minister of Finance. Health Professions Act regulation is within Minister of Health''s powers under section 47. No parliamentary vote required for post creation within a DoRA conditional grant. A National Treasury Section 76 framework for the grant conditions requires National Treasury concurrence and a MINMEC health resolution.',
    'GNU parties broadly support job creation in health — politically uncontroversial. NEHAWU and PSA (public sector unions) support absorption into permanent posts but will resist stipend-based CHW employment; the professional salary model addresses this. National Treasury will require performance conditions and sunset provisions to prevent permanent additions to provincial compensation baselines. The DoH must demonstrate that posts are clinically necessary, not merely a jobs programme.',
    'Ethiopia''s Health Extension Worker programme (43,000+ workers at community level) reduced child mortality by 40% over 15 years — the largest African CHW programme and directly relevant. Brazil''s Agentes Comunitários de Saúde (310,000 professionals) professionalised and salaried through the SUS system provides a legal and institutional model. India''s ASHA programme demonstrates scale but the stipend-only model is the cautionary counterexample SA should avoid.'
);

-- ── ID 107: TB Elimination National Acceleration Programme ───────────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    107,
    'South Africa carries the world''s highest absolute TB burden — approximately 300,000 new TB cases per year and 56,000 deaths — driven by a 60% TB/HIV co-infection rate, overcrowded housing, mining occupational exposure, and historically weak active case finding. The national TB programme is funded at R9 billion/year against an estimated need of R18 billion. The Stop TB Partnership''s End TB Strategy targets a 90% reduction in TB incidence and deaths by 2030 relative to 2015 baselines; SA is not on track. The National TB Control Programme has identified three high-impact interventions: (1) active case finding (ACF) using mobile GeneXpert units in high-burden communities; (2) scale-up of shorter, more effective treatment regimens (BPaL-M for drug-resistant TB); and (3) TB preventive therapy (TPT) for all people living with HIV and household contacts. The TB Acceleration Programme requires doubling the TB budget and an inter-departmental response including DHS, DPW (mining health), DPME (outcome targets), and DoL.',
    '[
      {"step":1,"title":"TB Programme Funding Doubling","description":"Increase the TB sub-programme allocation from R9 billion to R18 billion over 3 years through a dedicated TB Acceleration Conditional Grant: (a) R3 billion increase at 2025 MTBPS; (b) further R3 billion at 2026 Budget; (c) allocate R2 billion for capital: mobile GeneXpert units (300 additional units at R1.5 million each), laboratory network upgrades at NHLS, and community TB screening infrastructure","timeline":"2025 MTBPS to 2027 Budget","responsible_party":"National Treasury / DoH"},
      {"step":2,"title":"Active Case Finding Scale-Up","description":"Deploy 300 additional mobile GeneXpert units to the 30 highest-burden districts: (a) community screening campaigns targeting mining communities, informal settlements, and correctional facilities; (b) train 5,000 CHWs as TB screening agents; (c) target notification rate increase from 520/100,000 to 700/100,000 by 2027 through improved detection; (d) integrate TB screening into all PHC clinic visits (index case testing for all TB-positive patients'' household contacts)","timeline":"2025–2027","responsible_party":"DoH / NHLS / Provincial Health Departments / CHW programme"},
      {"step":3,"title":"BPaL-M Regimen Scale-Up","description":"Expand access to BPaL-M (Bedaquiline, Pretomanid, Linezolid, Moxifloxacin) for drug-resistant TB: (a) procure BPaL-M at scale through Stop TB Partnership''s Global Drug Facility; (b) train 200 specialist MDR-TB clinicians and 1,000 district nurses on BPaL-M administration and adverse event monitoring; (c) target 80% of eligible RR-TB patients on BPaL-M by 2027 from current 40%","timeline":"2025–2027","responsible_party":"DoH / NHLS / TB CHAMPS programme"},
      {"step":4,"title":"TB Preventive Therapy Scale-Up","description":"Achieve 90% TPT coverage for all eligible people living with HIV and all household contacts of TB cases: (a) integrate TPT into all ART initiation visits; (b) expand 3HP (isoniazid-rifapentine weekly for 3 months) as the preferred short-course TPT regimen; (c) target 500,000 new TPT initiations per year by 2026","timeline":"2025–2027","responsible_party":"DoH / SANAC / NGO implementing partners"},
      {"step":5,"title":"Occupational TB: Mining and Correctional Services","description":"Address the two highest-risk occupational settings: (a) enforce the Mine Health and Safety Act silica dust standards with DMRE inspections; (b) implement mandatory annual TB screening for all mineworkers; (c) roll out ACF programme in all correctional facilities (DCS partnership); (d) ex-mineworker TB/silicosis compensation scheme under MBOD to ensure medical access","timeline":"2025–2027","responsible_party":"DMRE / DoH / DCS / MBOD"},
      {"step":6,"title":"TB Outcome Monitoring and Accountability","description":"Establish the TB Acceleration Dashboard: (a) publish quarterly TB notification rates, treatment success rates, and TPT coverage by district; (b) District TB Accountability Compact signed by all 52 district health management teams; (c) annual Presidential TB report at the State of the Nation Address; (d) independent evaluation of programme against End TB targets by 2028","timeline":"Ongoing from 2025","responsible_party":"DoH / DPME / Stats SA"}
    ]',
    'Budget increase: 2025 MTBPS to 2027 Budget. GeneXpert deployment and CHW training: 2025–2026. BPaL-M scale-up: 2025–2027. TPT 90% coverage target: 2027. End TB review: 2028.',
    'Additional R9 billion/year to reach R18 billion total TB programme cost. Capital: R450 million for 300 GeneXpert units and laboratory upgrades. BPaL-M procurement: R2 billion/year (Global Drug Facility concessional pricing). Global Fund Round 7 application can cover R3–4 billion of additional costs.',
    'No new primary legislation required. Mine Health and Safety Act 29 of 1996 provides adequate powers for mining TB enforcement. Correctional Services Act 111 of 1998 section 12 provides for healthcare in correctional facilities. TB control is governed by the National Health Act 61 of 2003 and the Regulations Relating to Communicable Diseases. NHLS operates under the National Health Laboratory Service Act 37 of 2000.',
    'TB acceleration budget increases require National Treasury approval through the MTBPS and Budget. Mine Health and Safety Act enforcement requires DMRE/DMR Inspector cooperation. Global Fund Round 7 application is a sovereign process requiring DoH/National Treasury co-financing commitment. No legislative amendments required for programme scale-up.',
    'TB/HIV is a well-established public health priority with strong civil society support (TAC, TB HIV Care, SECTION27). The R9 billion funding gap is politically significant — framing the investment as cost-effective relative to hospitalisation costs (R200,000/MDR-TB case) is essential for National Treasury acceptance. Mining industry TB is politically sensitive given compensation litigation. GNU parties are broadly supportive of health outcomes investment.',
    'Peru achieved an 85% reduction in MDR-TB incidence over 2000–2020 through community-based directly observed therapy and comprehensive social support — the leading middle-income country model. Vietnam''s National TB Programme halved TB incidence over 2000–2018 through strong PHC integration. The Global Fund''s High Burden Country model provides a financing framework SA should maximise. South Africa''s own XTREME-TB BPaL-M trial data (Groote Schuur Hospital) demonstrate the local evidence base.'
);

-- ── ID 108: Primary Healthcare Platform Strengthening and CHW Integration ────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    108,
    'South Africa''s PHC platform consists of approximately 3,500 public clinics and community health centres (CHCs) handling 38 million patient visits per year. The platform is underfunded, under-staffed, and digitally fragmented — the HPRS patient records system is deployed in fewer than 20% of facilities. Ward-Based Primary Healthcare Outreach Teams (WBPHCOTs) deploy 43,000 CHWs in 4,278 wards nationally but pay stipends of R3,500/month (below minimum wage), provide minimal training, and operate without digital tools. The gap between PHC capability and the disease burden — HIV, TB, NCDs, maternal and child health — is the core structural failure of the public health system and the underlying reason NHI will require a long Phase 1 investment period. Strengthening the PHC platform involves: (1) permanent CHW employment at professional salary, (2) universal HPRS deployment with interoperable systems, (3) ward-based team integration with clinical governance structures, and (4) facility infrastructure rehabilitation.',
    '[
      {"step":1,"title":"HPRS Universal Deployment","description":"Accelerate deployment of the Health Patient Registration System (HPRS) to all 3,500 PHC facilities: (a) appoint a dedicated HPRS Programme Director within the DoH HISS Directorate; (b) procure tablets/devices for 43,000 CHWs and clinical workstations for 3,500 facilities; (c) establish HPRS interoperability with NHLS laboratory systems, PHDC pharmacy systems, and provincial DHIS2 reporting; (d) target 80% of facilities HPRS-enabled by end-2026","timeline":"2025–2026","responsible_party":"DoH HISS / DoH PHC Directorate / CSIR"},
      {"step":2,"title":"CHW Employment Formalisation","description":"Convert stipend-based CHW positions to permanent DoH posts: (a) gazette the CHW employment framework under the Health Professions Act; (b) establish minimum salary of R180,000/year CTC for community health workers; (c) implement 1-year HWSETA-accredited CHW certificate as minimum entry qualification; (d) absorb 30,000 of 43,000 current CHWs into permanent posts over 2026–2028 contingent on conditional grant funding","timeline":"2025–2028","responsible_party":"DoH / HPCSA / HWSETA / National Treasury"},
      {"step":3,"title":"Ward-Based Team Clinical Governance","description":"Integrate WBPHCOTs into the clinical governance structure of their linked PHC facilities: (a) appoint a professional nurse as Ward-Based Team coordinator for every 6 CHW teams; (b) weekly clinical case review at linked clinic; (c) standardised WBPHCOT scope of work: chronic disease monitoring, maternal health visits, immunisation outreach, TB contact tracing, and social needs referrals; (d) digital case management on HPRS mobile app","timeline":"2025–2026","responsible_party":"DoH PHC Directorate / Provincial Health Departments / HPCSA"},
      {"step":4,"title":"PHC Facility Infrastructure Rehabilitation","description":"Address the 5,000-item infrastructure backlog at public PHC facilities: (a) complete the Health Facility Condition Assessment for all 3,500 facilities by Q2 2026; (b) prioritise the 500 highest-need facilities for capital injection through the Health Facility Revitalisation Grant; (c) fast-track 200 facilities with critical water, sanitation, and electricity deficiencies through the DBSA Infrastructure Delivery Programme","timeline":"2025–2028","responsible_party":"DoH / DBSA / National Department of Public Works / Provincial Health Departments"},
      {"step":5,"title":"Essential Medicines and Supply Chain","description":"Strengthen the essential medicines supply chain to PHC: (a) implement the Pharmaceutical Distribution Depot (PDD) system in all 9 provinces; (b) automate stock replenishment using HPRS-linked pharmacy systems; (c) target zero stockouts for the 50 tracer medicines (ARVs, TB drugs, contraceptives, hypertension medications) at all PHC facilities; (d) annual stockout rate published by facility on DoH transparency portal","timeline":"2025–2027","responsible_party":"DoH / NDOH Procurement / National Treasury / SAPHRA"},
      {"step":6,"title":"NCD and Maternal Health Integration","description":"Strengthen the PHC package for non-communicable diseases and maternal health: (a) scale up the Integrated Chronic Disease Management (ICDM) model to all PHC facilities; (b) implement nurse-initiated and managed antiretroviral therapy (NIMART) training for all PHC nurses; (c) target 90% antenatal booking before 20 weeks in all districts; (d) integrate mental health screening into all PHC chronic disease visits","timeline":"2025–2027","responsible_party":"DoH / MRC SA / NIMART programme"}
    ]',
    'HPRS 80% deployment: end-2026. CHW formalisation: 2025–2028 (phased with conditional grant). Facility infrastructure: priority 500 facilities by 2027. NCD/ICDM integration: complete by 2027.',
    'HPRS deployment: R1.2 billion capital (devices, software, connectivity) plus R300 million/year maintenance. CHW formalisation: R5.4 billion/year additional (30,000 posts at R180,000/year). Facility infrastructure: R15 billion backlog (Health Facility Revitalisation Grant at R3 billion/year over 5 years). World Bank Health Systems Strengthening Project: R3 billion available for PHC investment.',
    'No new primary legislation required for HPRS deployment or supply chain. CHW scope-of-practice requires Health Professions Act 56 of 1974 section 47 regulations. Facility infrastructure funding operates under the DoRA Health Facility Revitalisation Grant schedule. SAPHRA (SA Health Products Regulatory Authority) regulations govern medicine supply under the Medicines Act 101 of 1965.',
    'HPRS deployment is within DoH administrative authority — no legislation required. CHW employment framework requires Ministerial regulation under Health Professions Act; HPCSA Board must gazette the registration category. Infrastructure funding allocated through annual DoRA amendment. Supply chain automation requires a DoH procurement framework directive under the PFMA Treasury Regulations.',
    'PHC strengthening has broad political support as the non-controversial foundation for NHI. CHW formalisation enjoys COSATU and NEHAWU support. The key political constraint is fiscal: R5+ billion/year for CHW salaries requires National Treasury conviction that outcomes justify the cost. The HPRS and stockout transparency portal create accountability mechanisms that build political legitimacy for the investment. DA and GNU parties support visible service delivery improvements at PHC level.',
    'Brazil''s SUS (Unified Health System) achieved near-universal PHC access through the Family Health Strategy and Agentes Comunitários programme — the most comparable model for a large, unequal middle-income country. Thailand''s Village Health Volunteers programme (1 million volunteers, salaried team supervisors) demonstrates the ward-based model at scale. The WHO Primary Health Care Performance Initiative provides the monitoring framework SA should adopt. Rwanda''s CHW system has been cited by WHO as the gold standard for sub-Saharan Africa.'
);

-- ── ID 109: Mental Health Services Expansion and Care Act Reform ──────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    109,
    'Fewer than 20% of South African adults with mental disorders access any treatment; the treatment gap is the widest of any major health condition. The Life Esidimeni tragedy (2016–2017, 144 deaths after mass discharge from NGO psychiatric facilities) exposed the catastrophic consequences of deinstitutionalisation without community service investment. The SA National Mental Health Policy Framework and Strategic Plan 2023–2030 sets targets for community-based mental health teams, integration of mental health into PHC, and a revised legal framework. The Mental Health Care Act 17 of 2002 requires amendment to strengthen patients'' rights, update involuntary admission procedures, and create a legal basis for community mental health teams. The funding gap is estimated at R5 billion/year above the current R7 billion mental health budget. The 1,000-team community mental health model (psychiatrist/psychologist/social worker/psychiatric nurse per district team) is the core service delivery innovation.',
    '[
      {"step":1,"title":"Mental Health Care Act Amendment","description":"Table the Mental Health Care Act Amendment Bill in Parliament: (a) update involuntary admission procedures (72-hour assessment, independent review board); (b) create legal status for Community Mental Health Treatment Orders as alternatives to hospitalisation; (c) strengthen patient rights enforcement under the South African Human Rights Commission; (d) align with CRPD (UN Convention on the Rights of Persons with Disabilities) and Mental Health Action Plan 2013–2030 principles","timeline":"2025–2026","responsible_party":"DoH / DoJ / Parliament"},
      {"step":2,"title":"Community Mental Health Team Deployment","description":"Deploy 500 Community Mental Health Teams by 2027 (target 1,000 by 2030): (a) each team comprises 1 psychiatric nurse, 1 social worker, 1 community counsellor, and access to a psychiatrist; (b) teams serve a ward cluster of 5–7 wards; (c) integrate with WBPHCOTs for psychosocial support; (d) establish 52 District Mental Health Coordinators (1 per district health management team)","timeline":"2025–2027","responsible_party":"DoH / HPCSA / SACSSP"},
      {"step":3,"title":"PHC Mental Health Integration","description":"Integrate mental health into the standard PHC package at all 3,500 facilities: (a) train all PHC nurses in the WHO Mental Health Gap Action Programme (mhGAP) — 5-day training for diagnosis and treatment of common conditions (depression, psychosis, substance use, child mental health); (b) deploy mobile telepsychiatry for rural PHC facilities; (c) target 50% of PHC facilities providing mhGAP-level mental health services by 2027","timeline":"2025–2027","responsible_party":"DoH / HPCSA / WHO SA"},
      {"step":4,"title":"Mental Health Funding Increase","description":"Increase the mental health budget from R7 billion to R12 billion/year over MTEF: (a) dedicated Mental Health Sub-Programme within the DoH budget programme; (b) conditional grant component for provincial community mental health teams; (c) engage SAMHSA (US), WHO, and Wellcome Trust for technical and financial co-investment; (d) target mental health expenditure of 12% of total health budget (current 5%)","timeline":"2025 MTBPS to 2028","responsible_party":"DoH / National Treasury"},
      {"step":5,"title":"Substance Use and Rehabilitation Services","description":"Expand substance use disorder treatment capacity: (a) 50 new community-based rehabilitation centres in high-burden areas through NICRO and registered NGO partnerships; (b) mandatory SAPS-DoH referral pathway for substance-related arrests (diversion from criminal justice); (c) naloxone availability at all PHC facilities and ambulance services for opioid overdose; (d) school-based mental health and substance use prevention through the DBE LifeSkills curriculum","timeline":"2025–2028","responsible_party":"DoH / DSD / SAPS / DBE"},
      {"step":6,"title":"Life Esidimeni Accountability and NGO Framework","description":"Implement the Life Esidimeni Arbitration Award recommendations: (a) establish a Gauteng Mental Health Monitoring Committee with civil society representation; (b) develop a national NGO accreditation framework for mental health facilities under OHSC; (c) all NGO mental health facilities to be licensed and inspected annually; (d) publish the National Mental Health Service Audit annually","timeline":"2025–2027","responsible_party":"DoH / OHSC / SAHRC / Gauteng DoH"}
    ]',
    'Mental Health Care Act amendment: tabled 2025, passed 2026. Community Mental Health Teams: 500 deployed by 2027, 1,000 by 2030. PHC mhGAP integration: 50% facilities by 2027. Budget: R12 billion/year by 2028.',
    'Additional R5 billion/year at full implementation. Community Mental Health Teams (1,000): R3 billion/year (salary and operational). mhGAP PHC training: R200 million capital. Telepsychiatry infrastructure: R100 million. NGO rehabilitation centres (50): R500 million capital. Wellcome Trust and WHO co-financing can contribute R300–500 million for capacity building.',
    'Mental Health Care Act 17 of 2002 amendment required (new legislation through Parliament). CRPD ratification requires compliance assessment. OHSC accreditation framework for mental health NGOs requires regulations under the National Health Act 61 of 2003 section 79. Substance use treatment facilities governed by Prevention of and Treatment for Substance Abuse Act 70 of 2008.',
    'Mental Health Care Act amendment requires ordinary legislative process in Parliament. The Departments of Health and Justice co-lead the amendment. OHSC NGO accreditation framework requires Ministerial gazette under the National Health Act. Community Mental Health Treatment Orders require the amended MHC Act before legal deployment. No regulations required for mhGAP PHC integration — this is a training and service protocol matter.',
    'Mental health has received more attention post-Life Esidimeni, with strong civil society and media pressure for reform. The SAHRC arbitration award created legal accountability obligations. The ANC and DA support community-based mental health as a cost-effective alternative to institutionalisation. Budget pressure is the primary constraint; NGO sector capacity provides an implementation vehicle that reduces public sector hiring requirements. COSATU supports psychosocial services as part of the broader health system expansion.',
    'The UK''s Improving Access to Psychological Therapies (IAPT) programme achieved 50% recovery rates for common mental disorders at PHC level at low cost — a model for PHC integration. Chile''s National Mental Health Programme (2001) integrated mental health into primary care and reduced the treatment gap from 85% to 60% over a decade. WHO''s mhGAP programme is implemented across 100+ countries; SA has the infrastructure to deploy it rapidly through existing CHW and PHC training systems.'
);

-- ── ID 110: Tobacco Products and Electronic Delivery Systems Control Act: Passage ─────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    110,
    'South Africa''s tobacco control legislation (Tobacco Products Control Act 83 of 1993, last substantively amended in 2008) is among the weakest in the region. The Control of Tobacco Products and Electronic Delivery Systems Bill was tabled in 2022 and passed Committee stage in 2023 but has stalled in the National Assembly following intensive tobacco industry lobbying, including contested public participation submissions from British American Tobacco SA. The Bill introduces plain packaging (graphic health warnings on 90% of packaging), prohibition on flavoured tobacco and e-cigarettes, expanded smoke-free zones (workplaces, vehicles with children), and SAPS enforcement powers. WHO FCTC Article 8 and 13 compliance requires the Bill''s passage. The economic case is compelling: smoking costs SA R60 billion/year in health system costs and productivity losses.',
    '[
      {"step":1,"title":"Parliamentary Passage of the Bill","description":"Prioritise the Bill in the National Assembly programme: (a) schedule National Assembly debate and vote in Q2–Q3 2025; (b) DoH Parliamentary Office to respond to all public objections systematically and rebut tobacco industry submissions with peer-reviewed evidence; (c) engage DA, ANC, and IFP MPs who have expressed reservations — provide economic cost data and FCTC compliance briefings; (d) obtain Presidential assent within 30 days of passage","timeline":"Q2–Q3 2025","responsible_party":"DoH / Parliamentary Office / National Assembly"},
      {"step":2,"title":"Plain Packaging Regulations and Implementation","description":"Gazette plain packaging regulations within 6 months of Presidential assent: (a) 90% graphic health warning on all tobacco products; (b) standardised packaging font and colour specifications; (c) 18-month phased compliance period for industry to redesign and produce compliant packaging; (d) appoint a Plain Packaging Compliance Committee under SAPS/NRCS to manage the rollout","timeline":"6 months post-assent; compliance 18 months post-gazette","responsible_party":"DoH / NRCS / SAPS"},
      {"step":3,"title":"E-Cigarette and ENDS Regulatory Framework","description":"Gazette ENDS (Electronic Nicotine Delivery Systems) regulations: (a) nicotine concentration caps (20 mg/mL maximum); (b) flavour prohibition (menthol, fruit, candy flavours prohibited); (c) childproof packaging requirements; (d) prohibition on ENDS marketing directed at persons under 18; (e) SAHPRA classification of therapeutic nicotine devices vs. recreational ENDS","timeline":"12 months post-assent","responsible_party":"DoH / SAHPRA / NRCS"},
      {"step":4,"title":"Smoke-Free Zone Expansion and Enforcement","description":"Implement expanded smoke-free zones: (a) all enclosed workplaces, public transport, vehicles carrying children, within 10m of entrances to public buildings; (b) train SAPS and municipal law enforcement on enforcement procedures and on-the-spot fines; (c) public awareness campaign through GCIS — target youth and school communities; (d) DoH/SAPS quarterly compliance inspections","timeline":"12–18 months post-assent","responsible_party":"DoH / SAPS / Municipalities / GCIS"},
      {"step":5,"title":"Illicit Tobacco Trade Countermeasures","description":"Address the illicit tobacco market (estimated 30–40% of SA market): (a) implement a track-and-trace system on all tobacco products (SARS/ITAC joint enforcement); (b) strengthen SAPS and SARS customs enforcement at border posts; (c) develop an inter-departmental illicit tobacco task team (SARS, SAPS, DoH, ITAC); (d) engage with neighbouring SACU member states on regional tobacco trade enforcement","timeline":"18–24 months post-passage","responsible_party":"SARS / SAPS / DoH / ITAC"},
      {"step":6,"title":"Cessation Services Integration","description":"Integrate tobacco cessation into the PHC platform: (a) train all PHC nurses in brief cessation counselling (5As method); (b) include cessation medicines (varenicline, nicotine replacement) in the Essential Medicines List; (c) establish a national Quitline through the DoH; (d) target a 5% absolute reduction in adult smoking prevalence by 2030","timeline":"2025–2027","responsible_party":"DoH / HPCSA / NHLS"}
    ]',
    'Bill passage: Q2–Q3 2025. Plain packaging regulations gazetted: Q1 2026. ENDS regulations: Q3 2026. Smoke-free zone enforcement: Q4 2026. Track-and-trace system: 2027.',
    'Legislative process: R5 million (DoH legal and parliamentary support). Regulations development: R10 million. Public awareness campaign (GCIS): R80 million. PHC cessation integration: R50 million. Enforcement training: R30 million. Total: approximately R175 million for implementation. Cost savings to health system: R60 billion/year (avoided tobacco-related disease).',
    'The Bill replaces the Tobacco Products Control Act 83 of 1993. Plain packaging requires gazette of regulations under the new Act. ENDS regulation requires SAHPRA classification decision under the Medicines Act 101 of 1965. Track-and-trace requires SARS regulatory gazette. Smoke-free zone enforcement requires municipal by-law alignment with the national legislation.',
    'The Bill has passed Committee stage in the National Assembly and requires a full house vote. Presidential assent triggers 90-day implementation planning commencement. All regulations are within the new Act''s regulation-making powers (Ministerial gazette — no further parliamentary process). Municipal by-laws must align with national legislation within 2 years; DoH will issue model by-law templates.',
    'Tobacco control legislation faces the most organised industry opposition of any health bill currently before Parliament. British American Tobacco SA, Philip Morris, and the illicit trade lobby have invested heavily in delaying passage. However, the WHO FCTC creates international treaty obligations and the FCTC Secretariat and Bloomberg Philanthropies are active supporters of South African advocacy. ANC health caucus supports the Bill; DA has members both supporting and opposing due to industry lobbying. The illicit trade argument is the most politically effective counter-argument and must be addressed in the Bill with track-and-trace provisions.',
    'Australia''s plain packaging legislation (2012) was the global first and survived a WTO challenge from Ukraine, Honduras, and Dominican Republic — SA must cite the WTO AB ruling in defending the policy. UK, France, New Zealand, and Ireland have all passed plain packaging with similar outcomes: initial industry legal challenges, followed by declining youth smoking initiation rates. Thailand''s smoke-free zone enforcement model is the leading ASEAN example. WHO FCTC Implementation Database shows 90% of SA''s competitors have stronger tobacco control — economic competitiveness is not a valid objection.'
);

-- ── ID 111: Provincial Health Department Turnaround Programme ─────────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    111,
    'Seven of nine provincial health departments received qualified audit opinions from the Auditor-General in 2023/24; Eastern Cape, North West, and Limpopo are in near-permanent financial crisis — characterised by infrastructure neglect, critical medicine stockouts, irregular expenditure above R5 billion per year, and chronic staff shortages. These departments collectively serve over 20 million people who are among South Africa''s most vulnerable. The Intergovernmental Fiscal Relations Act (Section 100 of the Constitution and the IGFRA) provides for national executive intervention in provinces that cannot or do not fulfill their constitutional obligations. A dedicated Provincial Health Turnaround Support Team within the DoH — modelled on the National Treasury''s provincial debt support programme — would provide embedded technical assistance, financial recovery plans, and conditional grant oversight alongside an escalating intervention framework.',
    '[
      {"step":1,"title":"Section 100 Intervention Assessment","description":"Commission a rapid diagnostic of the 3 worst-performing provincial health departments (Eastern Cape, North West, Limpopo): (a) AGSA and DoH joint diagnostic covering financial management, HR management, supply chain, and clinical governance; (b) produce a Province Health Recovery Plan for each within 90 days; (c) initiate Section 100(1)(a) written directives for specific corrective actions as a precursor to full intervention","timeline":"Q1–Q2 2025","responsible_party":"DoH / AGSA / National Treasury"},
      {"step":2,"title":"Provincial Health Turnaround Support Team","description":"Establish a dedicated PHTST unit within the DoH Director-General''s office: (a) team of 30 experts — CFO-level financial managers, supply chain specialists, HR practitioners, and clinical governance advisors; (b) embedded deployment in each target province for 12–18 months; (c) team funded through the DoH administration budget and National Treasury emergency capacity support; (d) modelled on COGTA''s Municipal Support Intervention teams","timeline":"Q2 2025","responsible_party":"DoH DG / National Treasury"},
      {"step":3,"title":"Financial Recovery Plans","description":"Implement province-specific Financial Recovery Plans: (a) accruals management — each province to produce a verified accruals register and 3-year clearance plan; (b) irregular expenditure prevention controls (enhanced approval thresholds, supply chain audit committees); (c) introduce provincial health department cash flow management frameworks with National Treasury weekly monitoring; (d) medicine and essential supply procurement aggregated through the NDOH central procurement office to reduce costs and prevent stockouts","timeline":"Q2 2025 – Q4 2026","responsible_party":"National Treasury / DoH / PHTST"},
      {"step":4,"title":"Infrastructure Rehabilitation Prioritisation","description":"Address the critical infrastructure backlog in target provinces: (a) commission a Health Facility Condition Assessment for all facilities in the 3 target provinces within 6 months; (b) prioritise 200 facilities with safety-critical deficiencies for emergency funding through the Health Facility Revitalisation Grant; (c) use DBSA Infrastructure Delivery Programme for project management in provinces with limited state capacity","timeline":"2025–2027","responsible_party":"DoH / DBSA / National DPW / Provincial Health Departments"},
      {"step":5,"title":"HR and Clinical Governance","description":"Stabilise the HR crisis in target provinces: (a) implement a provincial health department vacancy audit — freeze no post for longer than 12 months without Ministerial exemption; (b) deploy 500 rural allowance posts to target provinces from the Healthcare Worker Employment Grant; (c) establish a clinical governance accountability framework — adverse event reporting, mortality audits, and peer review at district hospital level","timeline":"2025–2026","responsible_party":"DoH / PHTST / DPSA"},
      {"step":6,"title":"Audit Improvement Targets","description":"Set binding audit improvement targets: (a) all 3 target provinces to achieve unqualified audit by 2026/27 (Eastern Cape and Limpopo) and 2027/28 (North West); (b) AGSA annual interim audits (not just year-end) to identify issues during the year; (c) DoH and National Treasury joint quarterly review with the Provincial MEC of Health; (d) Parliament''s Standing Committee on Public Accounts to prioritise annual health department hearings","timeline":"2025–2028","responsible_party":"DoH / AGSA / National Treasury / Parliament"}
    ]',
    'PHTST established: Q2 2025. Diagnostic and Financial Recovery Plans: Q3 2025. Infrastructure prioritisation: 2025–2026. Audit improvement targets: unqualified audits for 2 of 3 provinces by 2026/27.',
    'PHTST operational cost: R150 million/year (30-person embedded team with operational budget). Infrastructure emergency funding: R3 billion through the Health Facility Revitalisation Grant reallocation. National Treasury provincial debt support: R500 million available under the emergency support framework. Most costs are reallocation within existing grants, not new expenditure.',
    'Section 100 of the Constitution and the Intergovernmental Fiscal Relations Act 97 of 1997 provide the framework for national intervention. No new legislation required. The PFMA and National Treasury Regulations govern financial recovery plan implementation. The DoH can deploy a Section 100(1)(a) written directive under the Constitution without parliamentary approval. Full Section 100(1)(b) administration requires a Cabinet resolution and parliamentary notification within 14 days.',
    'Section 100 interventions are executive actions requiring Cabinet resolution for (1)(b) intervention. A written directive under Section 100(1)(a) requires only the relevant national Minister. The DoRA conditional grant conditions (under the Health Facility Revitalisation Grant and the HIV/TB grants) can be tightened through annual DoRA amendments — no separate legislation required. PHTST deployment is within the DoH DG''s administrative authority under the Public Service Act.',
    'Section 100 interventions have been politically contentious in SA (North West 2018 intervention faced ANC provincial resistance). The key to political feasibility is framing the PHTST as support, not punishment, and ensuring the intervention is co-designed with the provincial MEC and DG. GNU parties (DA, IFP) will broadly support accountability measures. ANC provincial structures may resist, but the severity of the audit findings creates pressure for national action. Linking the intervention to improved service delivery outcomes (visible to voters) provides political cover for the national department.',
    'Nigeria''s Basic Healthcare Provision Fund used federal-provincial co-investment with performance conditions to improve state-level health outcomes. The UK''s NHS Improvement (now NHS England) embedded support teams in failing NHS Trusts — directly analogous. Brazil''s SUS federal co-financing system includes punitive grant withdrawal for provinces that fail to meet minimum health expenditure thresholds. SA''s own National Treasury Municipal Finance Improvement Programme (MFIP) for local government is the closest domestic precedent.'
);

-- ── ID 112: Health Market Inquiry: Private Sector Reforms Implementation ──────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    112,
    'The Competition Commission''s Health Market Inquiry (HMI) Final Report (2019) identified concentrated market power throughout the private healthcare value chain — hospital groups (Netcare, Mediclinic, Life Healthcare dominate 75% of beds), dominant medical schemes (Discovery Health, 3 million members), and specialist fee inflation (South African specialists earn among the highest relative incomes globally). The HMI recommended 30 significant reforms; as of 2025, only 3 have been substantially implemented. Key outstanding reforms include: (1) mandatory supply-side regulation of private hospital groups through a Tariff Regulation Framework; (2) creation of a Health Market Conduct Regulator (HMCR) with price-setting powers; (3) prescribed minimum benefits (PMB) reform; (4) specialist reference pricing (mandatory fee schedules); and (5) transparency requirements for hospital costs and clinical outcomes. The DoH and dtic have been slow to implement — the HMCR has not been established and no mandatory tariff regulation is in force.',
    '[
      {"step":1,"title":"Health Market Conduct Regulator Establishment","description":"Establish the HMCR through the proposed Health Market Conduct Bill: (a) the HMCR is an independent statutory body with powers to set maximum tariffs for private hospitals and specialists, investigate anti-competitive conduct, and publish comparative pricing data; (b) board appointments with public health economics, actuarial, and consumer rights expertise; (c) funded through a levy on medical scheme premiums (0.1% of total contributions, approximately R400 million/year)","timeline":"Bill tabled 2025; HMCR operational 2026","responsible_party":"DoH / dtic / National Treasury"},
      {"step":2,"title":"Specialist Reference Pricing Implementation","description":"Implement mandatory specialist reference pricing as recommended by the HMI: (a) the HMCR publishes a National Reference Price List for all medical specialties — benchmark at median OECD specialist fee adjusted for South African GDP per capita; (b) medical schemes prohibited from reimbursing above 150% of the reference price without clinical justification; (c) publication of specialist billing data by specialty and province on the HMCR transparency portal","timeline":"HMCR establishment + 12 months; operational 2027","responsible_party":"HMCR / CMS / DoH"},
      {"step":3,"title":"Private Hospital Tariff Regulation","description":"Implement the Tariff Regulation Framework for private hospital groups: (a) HMCR authority to set maximum facility fees for hospital admissions, procedures, and ICU stays; (b) mandatory cost and outcome reporting by facility on a standardised template; (c) hospital group concentration analysis — Competition Commission investigation of acquisitions above a market share threshold; (d) target a 15% reduction in real private hospital cost growth within 5 years","timeline":"HMCR establishment + 18 months; operational 2027–2028","responsible_party":"HMCR / Competition Commission / DoH"},
      {"step":4,"title":"Prescribed Minimum Benefits Reform","description":"Revise the PMB framework under the Medical Schemes Act: (a) define PMBs as a clinically-derived benefit basket (not diagnosis-based entitlement), updated every 3 years by an independent clinical panel; (b) introduce co-payment limits for PMB services to prevent scheme design that circumvents PMBs; (c) mandate that all schemes offer a low-cost PMB-compliant option by 2027 to extend private coverage to low-income workers","timeline":"Regulations gazetted 2026","responsible_party":"CMS / DoH"},
      {"step":5,"title":"Low-Cost Benefit Options Expansion","description":"Fast-track the Low-Cost Benefit Option (LCBO) framework to bring employer group coverage to the 8 million employed uninsured: (a) CMS to gazette LCBO regulations by Q3 2025 (long delayed); (b) LCBOs capped at R500/month/member with standardised PMB compliance; (c) employer incentive through a Section 18A BBBEE scorecard credit for contributing to employee medical scheme membership; (d) target 1 million new LCBO members by 2027","timeline":"LCBO regulations Q3 2025; 1 million members by 2027","responsible_party":"CMS / DoH / National Treasury"},
      {"step":6,"title":"Outcome and Transparency Reporting","description":"Implement the HMI transparency recommendations: (a) mandatory annual publication of risk-adjusted clinical outcome data (mortality, readmission rates, infection rates) for all private hospitals and day clinics; (b) HMCR transparency portal with comparative facility and specialist pricing; (c) consumer information campaign on patient rights and comparison of private healthcare costs","timeline":"2026–2027","responsible_party":"HMCR / DoH / OHSC"}
    ]',
    'Health Market Conduct Bill tabled: 2025. HMCR operational: 2026. LCBO regulations: Q3 2025. Specialist reference pricing: 2027. Hospital tariff regulation: 2027–2028. Full HMI implementation: 2030.',
    'HMCR establishment: R400 million/year operating budget (funded by medical scheme levy). Legal and regulatory development: R50 million. HMCR Transparency Portal: R30 million capital. Economic benefits: estimated R15–30 billion/year in reduced private healthcare inflation if hospital and specialist fees are brought in line with international benchmarks.',
    'Health Market Conduct Bill (new primary legislation) required to establish HMCR with statutory price-setting powers. Medical Schemes Act 131 of 1998 amendment required for PMB reform and LCBO regulations. Competition Act 89 of 1998 provides existing framework for hospital merger oversight — no amendment required. NHI Act 20 of 2023 section 57 regulations can be used to phase HMI reforms into the NHI framework.',
    'Health Market Conduct Bill must be tabled in Parliament as primary legislation — DoH leads, dtic co-sponsors. LCBO regulations can be gazetted by the Minister of Health under current Medical Schemes Act powers — no new legislation required. PMB reform requires Medical Schemes Act amendment. Competition Commission hospital investigations proceed under the existing Competition Act without new legislation.',
    'The private healthcare industry (Discovery, Netcare, Mediclinic, Life) is well-resourced and will litigate both the HMCR establishment and specialist reference pricing. However, the HMI was a Competition Commission process with full legal standing; the recommendations have legal weight. The public interest case — private healthcare unaffordable for 85% of South Africans — is politically strong. DA''s constituency includes private healthcare users who would benefit from price transparency. GNU dynamics make legislation politically feasible if the DoH moves quickly. The ANC has been slow due to industry proximity; the NHI political environment provides urgency.',
    'The Netherlands'' Dutch Health Authority (NZa) combines private market regulation with reference pricing — the closest model to the proposed HMCR. Australia''s Private Health Insurance Act with its minimum coverage requirements and the Medicare Benefits Schedule as a reference fee system is directly applicable. Germany''s Krankenhaus Reform 2024 (hospital quality and tariff regulation) provides a current precedent for restructuring hospital markets. France''s CEPS (Economic Committee for Health Products) reference pricing model has achieved pharmaceutical cost control that is applicable to the specialist pricing component.'
);

-- ── ID 115: Government SMME Procurement: Enforcing the 30% Set-Aside ─────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    115,
    'National Treasury Instruction 3 of 2021/22 mandates that 30% of government procurement value (on contracts above R30 million) be subcontracted to SMMEs and cooperatives. Total government procurement is approximately R900 billion/year; the 30% set-aside target represents R270 billion — a potentially transformative demand signal for the SMME sector. Current compliance is below 10%, driven by: non-verification of SMME subcontractors, 30+ day payment delays that make subcontracting unattractive, absence of SMME supplier databases, and departments awarding subcontract obligations to BEE front companies rather than genuine SMMEs. The Public Procurement Act 28 of 2024 formalises the set-aside with audit consequences (AG must report on compliance) and requires a National SMME Supplier Database. DSBD and National Treasury share implementation responsibility.',
    '[
      {"step":1,"title":"National SMME Supplier Database","description":"Launch the National SMME Supplier Database (NSSD) under the DSBD/SEDA mandate: (a) integrate with National Treasury''s CSD (Central Supplier Database) through a verified SMME filter; (b) SMMEs to be verified against CIPC registration, SARS tax compliance, and SEDA registration; (c) publish NSSD as a public procurement tool by Q2 2026; (d) mandate all departments to source SMME subcontractors from the NSSD only","timeline":"Q2 2025 (design) to Q2 2026 (launch)","responsible_party":"DSBD / SEDA / National Treasury / CIPC"},
      {"step":2,"title":"30-Day Payment Enforcement","description":"Enforce 30-day payment obligations for SMMEs as subcontractors: (a) amend the PFMA Treasury Regulations to require that SMMEs on government contracts be paid within 30 days of invoice; (b) implement an automated payment monitoring system within National Treasury''s BAS; (c) publish a quarterly payment performance scorecard for all departments by SMME contract value; (d) impose escalation interest automatically on late payments to SMMEs","timeline":"Q1–Q3 2026","responsible_party":"National Treasury / DoL"},
      {"step":3,"title":"Departmental SMME Scorecards","description":"Implement annual SMME procurement scorecards for all national and provincial departments: (a) each department reports actual SMME subcontracting value as % of total procurement annually; (b) AG mandated under the Public Procurement Act to audit and report on compliance; (c) DGs to appear before the relevant parliamentary committee to explain compliance below 20%; (d) annual Cabinet report on aggregate SMME set-aside compliance published by DSBD","timeline":"2026 onwards (linked to 2025/26 procurement cycle)","responsible_party":"DSBD / AG / National Treasury / Parliament"},
      {"step":4,"title":"Public Procurement Act Regulations","description":"Gazette the implementing regulations under the Public Procurement Act 28 of 2024: (a) define qualifying SMME criteria (turnover <R50 million, majority SA-owned); (b) specify subcontracting verification requirements (site visits, invoicing documentation); (c) establish penalties for non-compliance — contract cancellation powers and procurement blacklisting for front companies; (d) create a procurement ombudsman function within the AG''s office for SMME complaints","timeline":"Regulations by Q4 2025","responsible_party":"National Treasury / DSBD"},
      {"step":5,"title":"Sector-Specific SMME Procurement Targets","description":"Implement sector procurement targets above the 30% minimum: (a) construction sector: 40% of sub-R100 million contracts reserved for SMMEs; (b) ICT and services: 35% SMME subcontracting target with verified local delivery; (c) fresh produce and catering: 50% SMME target for all government facility procurement (hospitals, schools, prisons); (d) SEDA-led supplier development programme to build SMME capacity in these sectors","timeline":"2026–2027","responsible_party":"DSBD / SEDA / National Treasury / Sector Departments"},
      {"step":6,"title":"Fintech Payment Innovation","description":"Implement supply chain financing for SMME government suppliers: (a) National Treasury to procure a supply chain finance platform (reverse factoring) allowing SMMEs to receive early payment (within 5 days) at a modest discount; (b) engage Nedbank, Standard Bank, and Absa to provide the factoring facility guaranteed by the IDC; (c) target 20,000 SMME government suppliers accessing early payment by 2027","timeline":"2026–2027","responsible_party":"National Treasury / IDC / Commercial Banks"}
    ]',
    'NSSD design: Q2 2025. Public Procurement Act regulations: Q4 2025. NSSD launched: Q2 2026. Payment enforcement system: Q3 2026. Annual SMME scorecards: from 2026/27 audit cycle. Supply chain finance platform: 2027.',
    'NSSD build and integration: R150 million capital (IT development, CSD integration). Supply chain finance facility: R5 billion guarantee from IDC (off-balance sheet contingent liability). Payment monitoring system: R50 million (BAS integration). Operational costs: R80 million/year (DSBD SMME verification team). Economic return: R27 billion additional SMME procurement per year if compliance reaches 10% increase.',
    'Public Procurement Act 28 of 2024 is the primary framework — implementing regulations required urgently. PFMA Treasury Regulations amendment for 30-day payment enforcement. National Credit Act may need amendment to accommodate reverse factoring instruments for government supply chain finance.',
    'Public Procurement Act 28 of 2024 empowers National Treasury to gazette all implementing regulations — no further primary legislation required for most provisions. PFMA Treasury Regulation amendment is within National Treasury''s administrative authority (no parliamentary vote). The supply chain finance instrument requires a memorandum of understanding between National Treasury, IDC, and participating banks — not legislation.',
    'SMME procurement support is politically uncontroversial — all parties support it rhetorically. The political challenge is enforcement: departments resist being held accountable for subcontracting compliance because it adds administrative cost and limits procurement flexibility. The AG compliance audit requirement in the Public Procurement Act creates real accountability that was absent from the Instruction Note. COSATU supports because SMME growth creates employment. BUSA and Business Unity SA support in principle but oppose prescriptive subcontracting mandates on large contracts.',
    'Malaysia''s Bumiputera set-aside programme (30% of government contracts) has been successfully implemented for 40+ years with a verified supplier database directly comparable to the proposed NSSD. South Korea''s Small Enterprise Purchase Reservation System (20% of government procurement reserved for SMEs) has been operational since 1999 with electronic monitoring. Kenya''s Access to Government Procurement Opportunities (AGPO) programme reserves 30% for youth, women, and persons with disabilities — the closest African model. US Small Business Administration set-asides (23% target, monitored annually) provide the compliance framework SA should benchmark.'
);

-- ── ID 116: SEFA Mandate Refocus: Growth-Oriented SMME Finance ────────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    116,
    'SEFA (Small Enterprise Finance Agency) is a DFI subsidiary of the IDC providing debt finance to SMMEs in the R50,000–R15 million range. It disbursed R2.1 billion in 2023/24 to 29,000 enterprises. However, SEFA''s portfolio is dominated by survival and subsistence finance — taxis, spazas, micro-retail — with a high impairment rate (21% NPLs) and negligible impact on productive capacity creation. High-growth SMMEs (annual turnover R5–50 million, in manufacturing, agro-processing, and technology) are the job-creating engine of a growing economy but are systemically underserved by both SEFA and commercial banks. A mandate refocus — shifting 40% of SEFA''s book to growth-oriented enterprises — requires: (a) a dedicated SMME Venture Debt facility (R5–50 million, 12-month approval); (b) sector specialisation in high-growth areas; (c) blended finance structures with IDC equity co-investment; and (d) streamlined credit decision processes.',
    '[
      {"step":1,"title":"SEFA Mandate Review and Board Resolution","description":"Commission a comprehensive SEFA mandate review: (a) independent analysis of SEFA''s portfolio composition, NPL rates, and employment outcomes by loan size and sector; (b) compare with comparable DFIs (DBN Nigeria, Kenya''s KUSSCO, Khula predecessor); (c) DSBD Minister table a revised mandate note to SEFA board and IDC board by Q3 2025; (d) mandate to include 40% growth finance target by 2028","timeline":"Q2–Q3 2025","responsible_party":"DSBD / IDC / SEFA Board"},
      {"step":2,"title":"SMME Venture Debt Facility","description":"Establish the SMME Venture Debt Facility within SEFA: (a) R2 billion facility for loans of R5–50 million to high-growth SMMEs; (b) 12-month maximum approval time (current average 18+ months); (c) blended structure: 60% SEFA senior debt + 20% IDC subordinated equity + 20% bank co-lending; (d) target sectors: agro-processing, light manufacturing, health technology, green economy supply chains; (e) dedicated deal team of 20 investment officers (recruit from commercial banks)","timeline":"Q4 2025 – Q3 2026","responsible_party":"SEFA / IDC / DSBD"},
      {"step":3,"title":"Credit Process Streamlining","description":"Redesign SEFA''s credit approval process: (a) implement a digital loan management system (LMS) replacing the current manual process; (b) credit scoring model for loans below R2 million (automated decisioning within 5 business days); (c) dedicated credit committee for R2–50 million growth loans (15-business-day decision SLA); (d) reduce documentation requirements by 40% through digital CIPC, SARS, and bank statement integration","timeline":"2025–2026","responsible_party":"SEFA CEO / IDC SMME Division"},
      {"step":4,"title":"Sector Hub Co-location with SEDA","description":"Co-locate SEFA regional offices with SEDA sector hubs to provide integrated finance and advisory services: (a) SEFA deal officers embedded in SEDA Agri-Tech Hub (KZN), Manufacturing Hub (Ekurhuleni), and Green Economy Hub (Cape Town); (b) SEDA advisory pipeline feeds qualified enterprises directly into SEFA credit process; (c) reduce SMME time-to-finance from 18 months to 6 months through integrated support","timeline":"Q1–Q3 2026","responsible_party":"SEFA / SEDA / DSBD"},
      {"step":5,"title":"Loss-Share Arrangement with Commercial Banks","description":"Establish a loss-share arrangement with commercial banks for co-lending to growth SMMEs: (a) government (SEFA/IDC) absorbs first-loss tranche (20–30%) on SMME growth loans originated by participating banks; (b) participating banks (Nedbank, Standard Bank, FNB, Absa) required to lend minimum R500 million/year each to qualifying growth SMMEs; (c) National Treasury guarantee framework for the first-loss facility (R1 billion guarantee); (d) annual reporting to NT on deployment and default rates","timeline":"2026–2027","responsible_party":"SEFA / IDC / National Treasury / Commercial Banks"},
      {"step":6,"title":"Outcome Measurement and Portfolio Review","description":"Implement outcome-based monitoring for SEFA''s growth portfolio: (a) collect annual turnover, employment, and export data from all growth-facility borrowers; (b) publish the SEFA Growth Finance Annual Impact Report; (c) DSBD Minister tabled annual SEFA performance report to Parliament; (d) three-year portfolio review to assess NPL rates, employment outcomes, and mandate compliance","timeline":"Ongoing from 2026","responsible_party":"SEFA / DSBD / Parliament"}
    ]',
    'Mandate review: Q3 2025. Venture Debt Facility launched: Q3 2026. Credit LMS deployed: Q2 2026. SEDA co-location: Q3 2026. Bank loss-share: 2027. Full impact reporting: from 2027.',
    'SMME Venture Debt Facility: R2 billion (from SEFA balance sheet and IDC capitalisation). Digital LMS: R80 million capital. IDC capitalisation for SEFA growth book: R1 billion (IDC equity injection). National Treasury first-loss guarantee: R1 billion (contingent liability). Additional IDC capitalisation may require National Treasury approval through the Budget.',
    'No new primary legislation required. SEFA was established as a subsidiary of the IDC under the Industrial Development Corporation Act 22 of 1940. Mandate changes are effected through an IDC board resolution and a revised DSBD shareholder compact. The loss-share arrangement with banks is a commercial agreement underpinned by a National Treasury guarantee framework (administrative, not legislative). The National Credit Act 34 of 2005 governs all SEFA lending products.',
    'SEFA mandate revision requires a DSBD Ministerial direction to the IDC board (shareholder compact) — no parliamentary vote. IDC capitalisation for SEFA requires a Cabinet-approved IDC appropriation increase through the Budget process. The bank loss-share guarantee requires National Treasury approval under section 70 of the PFMA. No primary legislation changes required.',
    'SEFA mandate reform has DSBD and SMME sector support. Commercial banks will support the loss-share arrangement as it de-risks SMME lending on their balance sheets. The IDC''s core industrial finance mandate aligns with the growth-finance reorientation. National Treasury will scrutinise the additional capitalisation and guarantee requirements carefully; NPL rate improvement must be demonstrated. The R2 billion Venture Debt Facility is small relative to the SMME finance gap (~R300 billion estimated by FinMark Trust) but is a credible starting point.',
    'Germany''s KfW (Kreditanstalt für Wiederaufbau) provides the model for a DFI that blends state guarantee with commercial bank co-lending for SME growth finance — SA''s SEFA/IDC structure should mirror the KfW-SME programme. Kenya''s Development Bank of Kenya (DBK) focus on growth-stage SME finance has achieved NPL rates below 5% through sector specialisation. Chile''s CORFO (Corporación de Fomento de la Producción) uses an intermediate credit model (lending through commercial banks with a government first-loss guarantee) that is directly applicable to the proposed loss-share arrangement.'
);

-- ── ID 118: Cannabis and Hemp Industry Licensing Rationalisation ──────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    118,
    'South Africa''s cannabis regulatory environment involves at least four regulatory bodies with overlapping and sometimes contradictory mandates: SAHPRA (medicinal cannabis cultivation and export licences), DALRRD (industrial hemp permits), SAPS (enforcement of remaining personal use restrictions), and SARS (tax classification). The Cannabis for Private Purposes Act 4 of 2024 decriminalises personal use and cultivation but does not create a commercial regulatory framework. Cannapreneurs (primarily small-scale, previously disadvantaged cultivators in traditional cannabis-growing regions — the Eastern Cape Pondoland, KZN, Mpumalanga) cannot access export licences due to the cost (R500,000+) and complexity of the SAHPRA Good Manufacturing Practice (GMP) compliance requirement. A potential R28 billion cannabis and hemp industry (European market demand for medical cannabis, domestic wellness and hemp food markets) requires a consolidated single-window Cannabis Industry Regulatory Authority (CIRA) that rationalises licensing, provides tiered GMP pathways for small cultivators, and coordinates export certification.',
    '[
      {"step":1,"title":"Cannabis Master Plan Finalisation","description":"Finalise the SA Cannabis Master Plan under the DSBD/DALRRD/DoH joint workstream: (a) produce a comprehensive mapping of the current regulatory landscape across all four departments; (b) market sizing study for medical cannabis exports (EU, UK, Australia), CBD wellness products, and hemp fibre/food; (c) legal opinion on the Cannabis for Private Purposes Act''s commercial implications; (d) gazette the Master Plan by Q4 2025","timeline":"Q2–Q4 2025","responsible_party":"DSBD / DALRRD / DoH / dtic"},
      {"step":2,"title":"Cannabis Industry Regulatory Authority Establishment","description":"Table the Cannabis Industry Regulatory Authority Bill: (a) CIRA absorbs licensing functions from SAHPRA (medicinal cannabis cultivation), DALRRD (hemp), and SARS (excise classification); (b) SAPS enforcement powers for remaining prohibited conduct retained; (c) CIRA board: 9 members with cannabis science, agronomy, trade, and legal expertise; (d) CIRA to issue all commercial cannabis licences within 90 days of application","timeline":"Bill tabled 2025; CIRA operational 2027","responsible_party":"Presidency / DSBD / DoH / Parliament"},
      {"step":3,"title":"Tiered Licensing Pathway for Small Cultivators","description":"Implement a tiered GMP-equivalent standard through CIRA: (a) Tier 1 (small cultivators, <2 hectares): simplified Good Agricultural Practice (GAP) standard rather than full pharmaceutical GMP — R50,000 compliance cost vs. R500,000; (b) Tier 2 (medium processors): Good Manufacturing Practice Lite standard; (c) Tier 3 (export-grade pharmaceutical producers): full EU-GMP compliance; (d) SEDA-run GAP certification support programme for Tier 1 cultivators","timeline":"CIRA operational + 6 months","responsible_party":"CIRA / SEDA / SAHPRA"},
      {"step":4,"title":"Export Facilitation and Market Access","description":"Develop cannabis export infrastructure: (a) bilateral pharmaceutical equivalency agreements with the EU (Narcotics Conventions compliance) and UK (MHRA), allowing SA medicinal cannabis exports without full EU-GMP re-certification; (b) ITAC cannabis export permit fast-track (5-day processing vs. current 30 days); (c) dtic cannabis trade mission programme to Germany (newly legalised recreational market) and Australia; (d) SA Cannabis Exchange — a digital B2B matching platform for buyers and SA cultivators","timeline":"2026–2027","responsible_party":"CIRA / dtic / ITAC / DIRCO"},
      {"step":5,"title":"Traditional Cultivator Empowerment Programme","description":"Design and implement a cultivator empowerment programme for traditional growing communities: (a) R500 million DSBD/IDC Cannabis SMME Fund for Pondoland, KZN, and Mpumalanga cultivators; (b) cooperative formation support through SEDA; (c) communal land resolution — DoRD to facilitate cannabis cultivation rights on communal land without triggering subdivision requirements; (d) SETA accredited cannabis cultivation and processing training courses","timeline":"2026–2027","responsible_party":"DSBD / IDC / SEDA / DALRRD / HWSETA"},
      {"step":6,"title":"Hemp Industry Development","description":"Develop the industrial hemp sector: (a) pilot 10,000 hectares of industrial hemp cultivation in Northern Cape and Free State; (b) DALRRD hemp seed variety registration — register 20 EU-standard low-THC varieties; (c) establish hemp processing value chain for fibre (building materials, textiles), seed oil (food), and CBD extraction; (d) incentivise hemp-based construction material manufacturers through IDC co-investment","timeline":"2026–2028","responsible_party":"DALRRD / IDC / DSBD"}
    ]',
    'Cannabis Master Plan gazetted: Q4 2025. CIRA Bill tabled: 2025. CIRA operational: 2027. Tiered licensing: 2027. Export agreements: 2026–2027. Cultivator fund: 2026.',
    'CIRA establishment: R200 million capital (funded by licence fees over 3 years). Cultivator Empowerment Fund: R500 million (IDC/DSBD). Hemp pilot programme: R100 million (DALRRD). SACanEx digital platform: R30 million. Total public investment: R830 million. Potential economic return: R28 billion industry GDP, 130,000 jobs by 2030.',
    'Cannabis Industry Regulatory Authority Bill (new primary legislation). Cannabis for Private Purposes Act 4 of 2024 amended to include commercial framework provisions. SAHPRA Act and Medicines Act 101 of 1965 amendments to transfer medicinal cannabis licensing to CIRA. Plant Breeders'' Rights Act and Plant Improvement Act amendments for hemp variety registration reform.',
    'CIRA Bill requires parliamentary passage as new primary legislation. The Departments of Health, Agriculture, and Trade and Industry co-sponsor. SAHPRA Act amendment requires parliamentary process. Hemp seed variety registration reform is within DALRRD regulatory authority — Ministerial gazette under the Plant Improvement Act. Export bilateral agreements are executive instruments negotiated through DIRCO — no parliamentary vote required.',
    'Cannabis legalisation and commercialisation have broad political support including in the ANC, DA, and EFF (which has championed legalisation). Traditional cultivating communities are a politically significant constituency. The small cultivator empowerment angle addresses transformation concerns. The key political risk is the Department of Health''s conservatism around medicinal cannabis and SAPS''s reluctance to cede enforcement jurisdiction. Co-opting SAPS into CIRA governance and ring-fencing enforcement powers mitigates this.',
    'Germany''s Cannabis Act 2024 (adult-use legalisation) is restructuring the European medical and recreational market — SA has a first-mover advantage in supplying this market. Canada''s Cannabis Act 2018 provides the comprehensive regulatory framework model, including the tiered licensing approach SA should adopt. Lesotho was the first African country to legalise medicinal cannabis cultivation (2017) and exports to European markets — a direct regional comparator and potential bilateral partner for SA quality standards. Zimbabwe''s medicinal cannabis licensing (2020) demonstrates rapid African market development.'
);

-- ── ID 119: SEDA Digital Transformation and Specialist Sector Hubs ────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    119,
    'SEDA (Small Enterprise Development Agency) operates 52 enterprise development centres serving approximately 100,000 SMMEs per year with business advisory, mentorship, and incubation services. Despite this reach, SEDA''s impact is limited by generic advisory services, low digital adoption, and the absence of sector specialisation. Most SEDA advisors are generalists without deep sector knowledge; the Agri-Tech, manufacturing, and green economy SMMEs that drive employment growth cannot access the specialist support they need from SEDA''s current model. A digital transformation — online advisory, AI-powered business diagnostics, and a digital SMME Academy — combined with physical sector-specialist hubs (Agri-Tech Hub in KZN, Manufacturing Hub in Ekurhuleni, Green Economy Hub in Cape Town) would materially increase SEDA''s impact on SMME survival rates (currently 50% fail within 3 years) and scale-up.',
    '[
      {"step":1,"title":"SEDA Digital Platform Launch","description":"Develop and deploy a SEDA Digital Platform: (a) online SMME diagnostic tool (AI-powered business health assessment: financial, operational, market readiness); (b) virtual advisory booking system with video-conference mentoring; (c) SMME Academy — self-paced online courses on financial management, digital marketing, export readiness, and HR; (d) integration with SARS eFiling, CIPC, and SEFA loan portal for seamless SMME registration and finance access","timeline":"Q3 2025 (design) to Q3 2026 (full deployment)","responsible_party":"SEDA / DSBD / CSIR"},
      {"step":2,"title":"Agri-Tech Hub: KZN","description":"Establish the SEDA Agri-Tech Hub in Pietermaritzburg (KZN): (a) co-located with the KZN Department of Agriculture and Rural Development and DALRRD regional office; (b) specialist advisors: 10 agro-processing value chain specialists, 2 precision agriculture technologists, 3 export market advisors; (c) shared infrastructure: cold chain demonstration facility, laboratory testing, and certification support for agri-exporters; (d) SEFA finance desk embedded in hub; (e) target 500 agri-SMMEs per year through intensive advisory","timeline":"Q2 2026","responsible_party":"SEDA / DSBD / KZN Province / DALRRD"},
      {"step":3,"title":"Manufacturing Hub: Ekurhuleni","description":"Establish the SEDA Manufacturing Hub in Ekurhuleni Industrial Park: (a) specialist advisors: 10 light manufacturing and metals specialists, 5 supply chain and logistics advisors, 3 quality management (ISO/SABS) advisors; (b) shared tooling and prototyping facility (CNC, 3D printing, welding bay) for light manufacturing SMMEs; (c) AIDC co-management for automotive supply chain SMMEs; (d) target 600 manufacturing SMMEs per year with a focus on Automotive Production and Development Programme (APDP) supply chain integration","timeline":"Q3 2026","responsible_party":"SEDA / AIDC / Ekurhuleni Metro / dtic"},
      {"step":4,"title":"Green Economy Hub: Cape Town","description":"Establish the SEDA Green Economy Hub in Cape Town (Bellville or Woodstock): (a) specialist advisors: solar and renewable energy systems, energy efficiency, waste beneficiation, and sustainable agriculture; (b) Green Finance Desk — SEFA and IDC green finance access; (c) GBCSA (Green Building Council) certification support; (d) link to Western Cape Green Economy Programme and the City of Cape Town''s Climate Action Department; (e) target 400 green economy SMMEs per year","timeline":"Q4 2026","responsible_party":"SEDA / IDC / City of Cape Town / Western Cape Government"},
      {"step":5,"title":"SEDA Advisor Professionalisation","description":"Upgrade SEDA''s advisory capacity: (a) require all SEDA sector hub advisors to hold sector-specific qualifications (agronomy, engineering, environmental science); (b) partner with SETA system (MERSETA, AgriSETA, ETDP SETA) for advisor CPD; (c) implement a SEDA Advisor Impact Score: each advisor tracked on client SMME turnover growth and job creation outcomes; (d) link advisor contracts to impact outcomes (move from inputs to outcomes-based contracting)","timeline":"2026–2027","responsible_party":"SEDA / DSBD / MERSETA / AgriSETA"},
      {"step":6,"title":"SMME Survival Rate Monitoring","description":"Implement an SMME outcome tracking system: (a) SEDA to track all clients for 3 years post-advisory using CIPC and SARS data; (b) publish annual SMME Survival and Growth Rate Report by hub and sector; (c) target SEDA-client 3-year survival rate increase from 50% to 65% by 2028; (d) independent evaluation of SEDA hub model by Q4 2028","responsible_party":"SEDA / DSBD / Stats SA","timeline":"From 2026 onwards"}
    ]',
    'Digital platform: Q3 2026. Agri-Tech Hub (KZN): Q2 2026. Manufacturing Hub (Ekurhuleni): Q3 2026. Green Economy Hub (Cape Town): Q4 2026. Advisor professionalisation: 2027. Survival rate target: 65% by 2028.',
    'Digital platform: R120 million capital (AI systems, platform development, IT). Three sector hubs: R300 million capital (R100 million each) for facilities, equipment, and 3-year operating costs. Advisor professionalisation: R50 million. Total: R470 million over 3 years. World Bank SMME Development Technical Assistance loan (R500 million available) can co-finance.',
    'No new primary legislation required. SEDA was established under the Small Enterprise Development Agency Act 9 of 2004 and operates under DSBD oversight. Hub establishment, digital platform, and advisor professionalisation are within SEDA''s existing mandate and administrative authority. The Green Finance Desk arrangement with IDC requires an MOU — not legislation.',
    'SEDA mandate expansion (sector hubs, digital platform) is within the DSBD Minister''s power to amend the SEDA mandate through a ministerial directive and revised performance agreement under the SEDA Act. World Bank loan for SMME development requires a National Treasury sovereign guarantee — a Cabinet resolution. No primary legislation amendments required.',
    'SMME support is politically uncontroversial — all parties support it. The sector hub model has been validated by the DTI (now dtic) Enterprise Development Hubs in automotive (AIDC) and aerospace, which are the model SEDA should replicate at scale. COSATU and the SMME sector federations (NAFCOC, FABCOS) support advisory and finance integration. Provincial governments will compete to host hubs — the selection of KZN, Ekurhuleni, and Cape Town reflects SMME density and sector comparative advantage.',
    'Germany''s Mittelstand support system (KfW + Chambers of Commerce + technical institutes) is the gold standard for sectoral SMME advisory at scale. South Korea''s Small Business Corporation (SBC) sector-specialist advisory centres have achieved 78% 5-year SMME survival rates. Singapore''s SME Centres co-located with industry associations provide integrated advisory and finance access — SEDA''s hub model closely resembles this. Mexico''s INADEM (before it was disbanded) provided a cautionary tale: digital transformation without sector specialisation and outcome measurement failed to improve SMME outcomes.'
);

-- ── ID 120: Cooperative Development: Outcome-Based Redesign ──────────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    120,
    'South Africa has 300,000+ registered cooperatives but fewer than 200,000 active members — the vast majority are dormant, inactive, or were registered for the purpose of accessing government grants without sustainable business operations. The DSBD''s cooperative development programme spends approximately R2 billion/year but produces poor economic outcomes: few cooperatives graduate to financial sustainability, employment is transient, and the programme has become a vehicle for patronage. The core design failure is funding cooperatives regardless of commercial viability — cooperatives receive grants for infrastructure and equipment without market linkages, business skills, or financial discipline. An outcome-based redesign would fund only cooperatives with demonstrated revenue streams (minimum R50,000/year trading), link SETA skills programmes to cooperative development, use cooperative banks (SANACO, Savings and Credit Cooperatives) for internal financial discipline, and introduce a mandatory cooperative business plan review by SEDA before any DSBD grant disbursement.',
    '[
      {"step":1,"title":"National Cooperative Audit and Database Rationalisation","description":"Commission a DSBD/Stats SA National Cooperative Audit: (a) verify which of 300,000+ registered cooperatives are actively trading; (b) deregister dormant cooperatives (no financial statements filed with CIPC for 3+ years) through CIPC deregistration process; (c) create a National Active Cooperative Registry with real-time CIPC and SARS integration; (d) publish the Cooperative Economy State of the Nation report annually","timeline":"Q2–Q4 2025","responsible_party":"DSBD / CIPC / Stats SA"},
      {"step":2,"title":"Outcome-Based Grant Design","description":"Redesign the DSBD Cooperative Incentive Scheme (CIS): (a) minimum eligibility: cooperative must demonstrate R50,000/year trading revenue before any infrastructure grant; (b) phased grant disbursement (30% on approval, 40% on trading milestone, 30% on employment milestone); (c) mandatory SEDA business plan review as gate before DSBD grant approval; (d) 3-year post-grant monitoring through SEDA; (e) cap grants at R500,000 per cooperative (current average R1.2 million with poor outcomes)","timeline":"Q3 2025 (redesign) to Q1 2026 (implementation)","responsible_party":"DSBD / SEDA"},
      {"step":3,"title":"SETA Skills Integration","description":"Link SETA skills programmes to cooperative development: (a) all cooperatives receiving DSBD grants must enrol members in an accredited SETA training programme relevant to their sector (AgriSETA for agricultural co-ops, MERSETA for manufacturing, CATHSSETA for tourism/hospitality); (b) skills development expenditure (SDL) relief for cooperatives during first 3 years; (c) SETA grants allocated to cooperative members as individuals — not lost due to cooperative registration status","timeline":"2026","responsible_party":"DSBD / DHET / SETA system"},
      {"step":4,"title":"Cooperative Bank and Finance Access","description":"Strengthen cooperative financial infrastructure: (a) FSCA to finalise the Co-operative Banks Development Agency (CBDA) framework and license 20 new Savings and Credit Co-operatives (SACCOs) in underserved areas by 2027; (b) Postbank to offer basic transactional accounts for cooperatives at zero monthly fee; (c) SEFA to establish a dedicated cooperative lending facility (R500 million) for cooperatives with 2+ years of trading history; (d) SANACO capacity building through DSBD grant","timeline":"2026–2027","responsible_party":"DSBD / CBDA / FSCA / SEFA / Postbank"},
      {"step":5,"title":"Market Linkage Programme","description":"Address the market linkage gap — the most common reason cooperatives fail: (a) integrate active cooperatives into the government SMME procurement database (NSSD) as a priority supplier category; (b) establish cooperative supply agreements with public institutions (school nutrition, hospital catering, government canteens) sourcing 20% of fresh produce from cooperative suppliers; (c) SEDA market development officers embedded in cooperative clusters","timeline":"2026–2027","responsible_party":"DSBD / SEDA / National Treasury / DBE / DoH"},
      {"step":6,"title":"Cooperative Sector Outcome Reporting","description":"Implement outcome-based monitoring: (a) DSBD publishes annual Cooperative Sector Outcomes Report — active cooperatives, employment, revenue, and SETA training completions; (b) link CIS grant continuation to programme-level employment and revenue outcomes; (c) independent 3-year evaluation of redesigned programme by Q4 2028; (d) DSBD to benchmark SA cooperative programme against ILO cooperative development indicators","timeline":"From 2026 onwards","responsible_party":"DSBD / Stats SA / ILO SA"}
    ]',
    'National Cooperative Audit: Q4 2025. CIS redesign implementation: Q1 2026. SETA integration: 2026. Cooperative bank framework: 2026–2027. Market linkage: 2026–2027. Outcome report: from 2026.',
    'CIS redesign reduces average grant from R1.2 million to R500,000 — budget neutral or saving R600 million/year on same number of grants. SEFA cooperative lending facility: R500 million (SEFA balance sheet). SACCO licensing programme: R50 million (FSCA/CBDA). Postbank integration: R20 million. Total new investment: R570 million. Net saving from CIS redesign: R600 million/year.',
    'No new primary legislation required. Co-operatives Act 14 of 2005 provides the framework; CIS redesign is within DSBD administrative authority. Co-operative Banks Act 40 of 2007 governs the CBDA and SACCO licensing; FSCA gazette of new licensing requirements required. SETA skills integration requires SETA Board resolutions — DHET facilitates but no legislation required.',
    'CIS grant redesign is within the DSBD Director-General''s administrative authority under the Co-operatives Act; no parliamentary vote required for programme design changes. SACCO licensing regulations under the Co-operative Banks Act require FSCA gazette — administrative process. SEFA cooperative lending facility is within SEFA board authority. Postbank account access requires DSBD-Postbank MOU.',
    'Cooperative programme reform is politically sensitive — the current model has significant political patronage embedded. The ANC has historically promoted cooperatives as a solidarity economy vehicle. The outcome-based redesign must be framed as rescuing the cooperative model from failure, not abandoning it. DA and GNU parties support the outcome-based approach. COSATU supports cooperative development but will monitor to ensure that cooperative employment is not used to suppress wages and formal employment.',
    'Mondragon Cooperative Corporation (Basque Country, Spain) — 80,000 member-employees, R80 billion turnover — is the global cooperative model; SA should study its governance and finance structures. Rwanda''s Cooperative Sector (600,000 members, agricultural focus) has achieved significant poverty reduction through market-linked cooperatives supported by district-level government advisors. Kenya''s SACCO sector (14 million members) demonstrates the savings and credit cooperative model SA should expand. Bolivia''s productive cooperative programme links government procurement to cooperative suppliers — directly applicable to the NSSD integration proposed here.'
);

-- ── ID 121: Informal Economy Integration: Simplified Tax and Municipal Trading Permits ─
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    121,
    'South Africa''s informal economy employs an estimated 2.8–3.2 million people (18% of total employment) in street trading, spaza shops, taxis, domestic workers, and informal services. This sector is largely invisible to the state: SARS''s Turnover Tax (for businesses with annual turnover below R1 million) has only 60,000 registered users despite an estimated 1.5 million eligible micro-enterprises. The barriers to formalisation are multiple: SARS registration complexity, annual municipal trading permits (often requiring multiple visits, queues, and fees), CIPC registration costs, and the perception that formalisation brings costs without benefits. A simplified integrated regime — a flat annual Micro-Enterprise Tax of R1,200 replaces both the Turnover Tax and the municipal trading permit fee, administered through a single digital interface — could formalise 500,000 micro-enterprises and generate R700 million/year in additional tax revenue while bringing entrepreneurs into financial services access.',
    '[
      {"step":1,"title":"Micro-Enterprise Tax Design","description":"SARS and National Treasury to design the simplified Micro-Enterprise Tax regime: (a) flat annual tax of R1,200 for businesses with annual turnover below R500,000 (covers PAYE replacement for owner-operators and business income tax); (b) replaces the current Turnover Tax and eliminates quarterly provisional tax filings; (c) annual registration renewal through USSD (*120*SARS#), WhatsApp, or a SEDA-assisted portal; (d) tax certificate replaces the municipal trading permit for street trading and spaza operations","timeline":"Q2–Q4 2025 (design); Q1 2026 (gazette)","responsible_party":"SARS / National Treasury / DSBD"},
      {"step":2,"title":"Digital Trading Permit Integration","description":"Integrate the Micro-Enterprise Tax certificate with municipal trading permits: (a) SALGA to develop a model municipal by-law amendment making a valid SARS Micro-Enterprise Tax certificate sufficient for street trading authorisation; (b) target 257 municipalities to adopt the model by-law by end-2026; (c) digital permit (QR-code based, verifiable on SARS website) issued within 24 hours of tax payment; (d) eliminate municipal permit queues as a formalisation barrier","timeline":"Model by-law gazetted Q2 2026; municipality adoption 2026–2027","responsible_party":"SARS / SALGA / DSBD / CoGTA"},
      {"step":3,"title":"SARS Registration Drive","description":"National SARS Micro-Enterprise Registration Campaign: (a) 6-month campaign targeting 500,000 new Micro-Enterprise Tax registrations; (b) SARS mobile units deployed in major taxi ranks, township commercial areas, and informal settlements; (c) SEDA enterprise centres process registrations as SARS-authorised agents; (d) incentive: registered micro-enterprises qualify for the government SMME procurement database (NSSD) and SEFA microfinance access","timeline":"Q2–Q4 2026","responsible_party":"SARS / SEDA / DSBD"},
      {"step":4,"title":"Financial Inclusion Linkage","description":"Link Micro-Enterprise Tax registration to financial services access: (a) registered micro-enterprises receive a standardised business credit profile shared with participating banks and microfinance institutions; (b) Postbank Business Account (zero-fee, no minimum balance) available to all registered micro-enterprises; (c) SEFA microfinance referral for registered businesses; (d) UIF registration automatically triggered on Micro-Enterprise Tax registration (ensuring social protection for informal workers)","timeline":"2026–2027","responsible_party":"SARS / FSCA / Postbank / SEFA"},
      {"step":5,"title":"Spaza Shop Compliance and Foreign Nationals","description":"Address the specific formalisation challenges in the spaza sector following the food safety incidents (2024): (a) the Micro-Enterprise Tax certificate includes a food safety compliance declaration for food traders; (b) SARS verification of South African ID or legal work permit as part of registration; (c) municipality health inspector inspections for food traders linked to the digital permit database; (d) amnesty for currently trading spaza operators to regularise within 6 months of programme launch","timeline":"2026","responsible_party":"SARS / Municipalities / DoH / Home Affairs"},
      {"step":6,"title":"Revenue and Formalisation Impact Assessment","description":"Monitor formalisation outcomes: (a) SARS to publish quarterly Micro-Enterprise Tax registration statistics disaggregated by province and sector; (b) Stats SA Quarterly Labour Force Survey to include informal economy formalisation tracker; (c) National Treasury to publish 3-year revenue impact assessment by 2028; (d) evaluate whether R1,200 flat rate is appropriately calibrated — review every 3 years","timeline":"From Q1 2026 onwards","responsible_party":"SARS / Stats SA / National Treasury"}
    ]',
    'Micro-Enterprise Tax design: Q4 2025. Gazette: Q1 2026. Municipal by-law adoption: 2026–2027. Registration campaign: Q2–Q4 2026. Postbank linkage: 2026. Revenue impact: 3-year assessment 2028.',
    'SARS system investment: R200 million (digital platform, USSD, mobile unit deployment). SEDA registration agent training: R30 million. GCIS awareness campaign: R50 million. Total investment: R280 million. Revenue gain: R700 million/year (500,000 registrations at R1,200 each), net gain R420 million/year after system costs. Additional financial inclusion benefit: 500,000 new business bank accounts.',
    'Turnover Tax reform requires amendment to the Income Tax Act 58 of 1962 (Schedule 1 — Turnover Tax tables) through the annual Taxation Laws Amendment Bill. Municipal trading permit legislation requires amendment to the Business Act 71 of 1991 and the City of Cape Town, eThekwini, and CoJ by-laws; SALGA model by-law recommended. UIF registration trigger requires an amendment to the Unemployment Insurance Act 63 of 2001.',
    'Turnover Tax reform is effected through the annual Taxation Laws Amendment Bill — National Treasury and SARS drive this. The Business Act 71 of 1991 amendment requires parliamentary process; DSBD leads. Municipal by-law alignment is administrative — SALGA issues a model by-law and municipalities adopt through council resolution. UIF trigger requires a brief amendment to the UIA. No constitutional issues.',
    'Informal economy formalisation has broad support across the political spectrum — the ANC''s township economy agenda, DA''s regulatory simplification agenda, and EFF''s economic inclusion agenda all align. The post-spaza food safety crisis (2024) has increased political urgency for formalisation with accountability. The R700 million/year revenue gain makes this fiscally attractive for National Treasury. Foreign national traders is the politically sensitive dimension — the registration requirement must be non-discriminatory but legally compliant with immigration status verification.',
    'Rwanda''s informal economy formalisation programme (Ubudehe classification and Mutuelle registration) achieved 95% registration of informal traders within 5 years — the leading African model. Ghana''s Domestic Micro Finance Tax Stamp (flat fee for informal traders) simplified compliance and increased informal sector revenue by 35%. Mexico''s REPECO (Régimen de Pequeños Contribuyentes) flat-tax regime for micro-enterprises registered 4 million informal businesses before being superseded — valuable positive and cautionary lessons. India''s Udyam registration for MSMEs (Aadhaar-linked, zero cost, instant digital certificate) registered 10 million enterprises in its first year — the digital registration model SA should replicate.'
);

-- ── ID 122: Enterprise and Supplier Development: Corporate Linkage Programme ─────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    122,
    'BBBEE scorecards require corporations to spend 3% of Net Profit After Tax on Enterprise and Supplier Development (ESD) — approximately R15 billion/year across the Johannesburg Stock Exchange-listed and large unlisted companies. However, ESD spend is poorly audited, poorly targeted, and frequently goes to box-ticking activities (golf sponsorships classified as mentorship, short training courses without market linkages) rather than sustainable SMME development. The BBBEE Commission has found that fewer than 30% of ESD spend results in measurable SMME growth outcomes. A National ESD Registry (SANAS-accredited ESD intermediaries), mandatory impact reporting (employment and turnover growth of beneficiary SMMEs, not just Rand spent), and a Supplier Development Matching Platform (SEDA-operated) connecting large corporations with verified SMME suppliers would transform R15 billion in ESD spend into a productive national economic resource.',
    '[
      {"step":1,"title":"National ESD Registry Establishment","description":"Establish the National ESD Registry through the BBBEE Commission: (a) SANAS-accreditation standard for ESD intermediaries (business development service providers, incubators, accelerators); (b) all ESD spend by BBBEE-scored entities must go through SANAS-accredited ESD intermediaries or directly to registered SMME beneficiaries; (c) BBBEE Commission to publish the National ESD Registry publicly with performance ratings; (d) non-accredited ESD spend disqualified from BBBEE scorecard from 2026","timeline":"Q2 2025 (standard design) to Q2 2026 (registry launch)","responsible_party":"BBBEE Commission / SANAS / dtic"},
      {"step":2,"title":"Mandatory ESD Impact Reporting","description":"Redesign the ESD scorecard elements to require outcome reporting: (a) replace Rand-spent metrics with outcome metrics — SMME beneficiaries'' annual turnover growth (minimum 20% per year required), employment creation, and SMME graduation rate; (b) B-BBEE verification agencies (BVAs) must conduct site visits and financial statement verification for ESD beneficiaries; (c) BBBEE Commission publishes annual ESD Outcomes Report by JSE sector; (d) companies with ESD spend below R5 million may use a simplified reporting format","timeline":"Scorecard amendments by Q4 2025; reporting from 2026/27","responsible_party":"dtic / BBBEE Commission"},
      {"step":3,"title":"Supplier Development Matching Platform","description":"Launch the SEDA Supplier Development Matching Platform (SDMP): (a) digital platform where corporations post supplier development opportunities (procurement needs, required certifications, volume estimates); (b) verified SMMEs from the NSSD match to opportunities based on sector, geography, and capability; (c) SEDA advisors facilitate initial introductions and supplier readiness assessments; (d) platform tracks contract awards and SMME performance for BBBEE reporting purposes","timeline":"Q1–Q4 2026","responsible_party":"SEDA / DSBD / dtic / BBBEE Commission"},
      {"step":4,"title":"Large Corporation ESD Targets by Sector","description":"Introduce sector-specific ESD minimum targets above the BBBEE baseline: (a) mining sector: 5% of NPAT (mines have large procurement budgets and local community development obligations); (b) financial services: 3.5% of NPAT with R10 million minimum to township-based fintechs and cooperatives; (c) construction: 40% of project procurement from registered SMMEs on all projects above R100 million; (d) SEDA sector hubs to manage ESD linkages for manufacturing and agro-processing SMMEs","timeline":"Sector codes amended 2026","responsible_party":"dtic / Sector BBBEE Councils / BBBEE Commission"},
      {"step":5,"title":"ESD Finance Blending","description":"Establish ESD Blended Finance vehicles: (a) ESD spend may be invested as patient equity in SMMEs (not only grants/loans) — amend BBBEE Codes to recognise equity ESD as 1.5x multiplier; (b) SEFA administers a National ESD Fund Pool — corporations contribute ESD allocations to SEFA for deployment to verified growth SMMEs, reducing individual corporation administration costs; (c) IDC manages an ESD co-investment programme (R1 billion/year) for high-growth SMME equity alongside corporate ESD equity","timeline":"Codes amendment 2026; Fund pool operational 2027","responsible_party":"dtic / SEFA / IDC / BBBEE Commission"},
      {"step":6,"title":"BBBEE Fronting Enforcement","description":"Strengthen BBBEE fronting detection in ESD: (a) BBBEE Commission ESD-specific investigations unit (10 dedicated investigators); (b) automated cross-reference of ESD beneficiary CIPC registrations with BBBEE scorecard verification data; (c) public register of verified ESD beneficiaries (preventing same SMME being claimed by multiple corporations); (d) penalties for fronting in ESD — BBBEE certificate suspension for 5 years for the corporation and the BVA","timeline":"2025–2026","responsible_party":"BBBEE Commission / dtic / NPA"}
    ]',
    'ESD Registry: Q2 2026. Scorecard outcome amendments: Q4 2025. SDMP platform: Q4 2026. Sector code amendments: 2026. ESD Fund Pool: 2027. Fronting enforcement: 2025–2026.',
    'National ESD Registry IT system: R80 million (SANAS/BBBEE Commission). SDMP platform: R60 million (SEDA digital build). ESD investigations unit: R50 million/year. Total public investment: R190 million capital plus R50 million/year. Private sector ESD spend leveraged more effectively: R15 billion/year with 30% improvement in impact = R4.5 billion/year additional productive ESD.',
    'BBBEE Codes of Good Practice amendment (Gazette No. ESD element redesign) under the Broad-Based Black Economic Empowerment Act 53 of 2003 (section 9) — Ministerial gazette, no parliamentary vote. SANAS accreditation standard for ESD intermediaries under the SANAS Act. B-BBEE Act amendments for fronting penalties require parliamentary process if existing section 26 penalties are insufficient.',
    'BBBEE Codes ESD element amendment is within the dtic Minister''s power under section 9 of the BBBEE Act — gazetted without parliamentary vote. The ESD Fund Pool administered by SEFA requires a SEFA board resolution and IDC/DSBD approval. SANAS accreditation standard is within SANAS''s statutory authority. BBBEE fronting penalties under section 26 of the BBBEE Act are already in force; the investigations unit is an administrative enhancement.',
    'ESD reform will face opposition from BVAs (who benefit from the current lenient verification regime) and from large corporations resistant to outcome-based reporting. However, the BBBEE Commission''s published data on poor ESD outcomes makes the political case compelling. The dtic and DSBD are aligned on reform. ANC, DA, and EFF all rhetorically support economic transformation through genuine SMME development. The multiplier for equity ESD and the SEFA Fund Pool creates a positive incentive rather than just penalising non-compliance.',
    'South Africa''s own BBBEE regime is the international reference for transformation-linked procurement and supplier development — no direct external comparator exists. Brazil''s Lei de Inovação provides a model for corporation-SMME technology transfer that SA should consider adding to the ESD framework. Malaysia''s Vendor Development Programme (direct corporate-SMME linkage with government facilitation) achieved significant Bumiputera SMME scale-up. The UK''s Social Value Act (requiring public procurement to consider social and economic outcomes) provides a complementary model for extending ESD logic into public procurement.'
);

-- ── ID 123: Just Energy Transition SMME Finance Facility ─────────────────────────────
INSERT OR IGNORE INTO implementation_plans (
    idea_id, roadmap_summary, implementation_steps, estimated_timeline,
    estimated_cost, required_legislation, draft_legislation_notes,
    political_feasibility_notes, international_precedents
) VALUES (
    123,
    'South Africa''s Just Energy Transition Investment Plan (JET-IP), published in November 2022 and updated in 2024, mobilises R1.5 trillion (approximately $80 billion) over 20 years for the decarbonisation of the electricity sector, transition of coal-dependent communities, electrification of transport, and green hydrogen development. The JET-IP was backed by an $8.5 billion initial commitment from the International Partners Group (EU, UK, US, France, Germany) and subsequent pledges from the US DFC, EIB, and KfW. While the JET-IP focuses on large infrastructure (IPP renewable energy, Eskom grid, coal mine rehabilitation), the SMME supply chain — solar panel installation, inverter maintenance, EV charging infrastructure, green building materials, biogas development, waste-to-energy — represents hundreds of thousands of potential SMME jobs and enterprises that are currently undersupported. A dedicated JET-SMME Finance Facility (R5 billion over 3 years, via SEFA/IDC) targeting 5,000 SMMEs in the JET supply chain, with blended finance and technical assistance from international partners (GIZ, EU Impact Finance, US DFC), would accelerate the inclusive dimensions of the transition.',
    '[
      {"step":1,"title":"JET-SMME Finance Facility Design","description":"SEFA, IDC, and DSBD to co-design the JET-SMME Finance Facility: (a) R5 billion facility over 3 years — R2 billion SEFA debt, R1.5 billion IDC equity/mezzanine, R1.5 billion international partner concessional finance (GIZ, EU, US DFC); (b) target sectors: solar installation and maintenance SMMEs, EV supply chain (charging, batteries, servicing), green building and retrofitting, biogas and agricultural waste beneficiation, water and energy efficiency services; (c) loan sizes R500,000–R20 million, 7-year repayment at blended rate of 8–10% (below commercial prime-linked rates); (d) technical assistance component funded by GIZ (R200 million over 3 years)","timeline":"Q2–Q4 2025 (design and international partner commitments)","responsible_party":"SEFA / IDC / DSBD / National Treasury"},
      {"step":2,"title":"International Partner Mobilisation","description":"Secure international partner co-financing commitments: (a) engage GIZ South Africa office for technical assistance (business development, SMME advisory) funding commitment; (b) EU Impact Finance for first-loss guarantee (15% of facility) on SMME JET loans; (c) US DFC (Development Finance Corporation) for senior co-lending on EV and clean energy SMMEs; (d) KfW for concessional SMME green finance tranche; (e) present the JET-SMME Facility to the G20 sustainable finance working group as an inclusive JET model","timeline":"Q2–Q3 2025","responsible_party":"National Treasury / DIRCO / IDC / SEFA"},
      {"step":3,"title":"JET-SMME Supply Chain Mapping","description":"Map the SMME opportunity within the JET value chain: (a) commission a CSIR/SEDA study quantifying the SMME procurement demand from the R1.5 trillion JET pipeline — disaggregated by sector, province, and SMME capability requirement; (b) identify 100 large JET contractors (IPP developers, EPC firms) with SMME ESD obligations in their project finance covenants; (c) publish the JET-SMME Opportunity Map as a public resource for entrepreneurs and investors","timeline":"Q3–Q4 2025","responsible_party":"CSIR / SEDA / IPP Office / dtic"},
      {"step":4,"title":"JET-SMME Technical Assistance Programme","description":"Implement a JET-SMME Technical Assistance programme: (a) GIZ-funded: 50 SEDA-embedded JET advisors (solar, EV, green building specialists) deployed in the 10 highest-JET-activity municipalities; (b) training on renewable energy installation and maintenance (EWSETA-accredited, 3-month courses for artisans); (c) green business certification (GBCSA Green Star Lite for small contractors); (d) export readiness support for SMMEs targeting the African clean energy market (SADC JET opportunities)","timeline":"2026–2027","responsible_party":"SEDA / GIZ / EWSETA / GBCSA"},
      {"step":5,"title":"Coal Community SMME Just Transition","description":"Dedicated SMME support for Mpumalanga coal transition communities: (a) 500 SMME JET loans specifically for Mpumalanga-based enterprises transitioning from coal services to renewable energy services; (b) Presidential Climate Commission JET-SMME Compact — local content targets in Mpumalanga for all JET infrastructure projects; (c) coal mine rehabilitation SMMEs (R10 billion rehabilitation budget) — preferential procurement for local SMMEs; (d) Mpumalanga SEZ expansion to include a Green Industrial Zone for JET manufacturing","timeline":"2026–2028","responsible_party":"SEFA / IDC / Presidential Climate Commission / Mpumalanga Province"},
      {"step":6,"title":"JET-SMME Outcome Monitoring","description":"Implement outcome-based monitoring for the JET-SMME Facility: (a) SEFA and IDC publish quarterly JET-SMME Facility Report — loans disbursed, SMMEs financed, employment created, MW of renewable energy installed by SMME-financed projects; (b) environmental additionality reporting (tonnes of CO2 avoided through SMME-installed solar and efficiency measures); (c) independent mid-term evaluation at 18 months; (d) scale decision at 3 years based on deployment rate and NPL outcomes; (e) report to the JET Inter-Ministerial Committee","timeline":"From Q1 2026 onwards","responsible_party":"SEFA / IDC / DSBD / Presidential Climate Commission / DPME"}
    ]',
    'Facility design and international commitments: Q4 2025. JET-SMME Opportunity Map: Q4 2025. Facility launch: Q1 2026. 1,000 SMMEs financed: end-2026. 5,000 SMMEs financed: end-2028. Coal community programme: 2026–2028.',
    'R5 billion facility over 3 years — R2 billion SEFA (existing balance sheet), R1.5 billion IDC, R1.5 billion international concessional (GIZ, EU, DFC — targeted as grants/first-loss). GIZ technical assistance: R200 million (grant). Total public investment: R3.5 billion domestic; R1.7 billion international. SMME technical assistance: R200 million (GIZ grant). JET-SMME Facility leverages 1:3 public-to-private capital ratio.',
    'No new primary legislation required. SEFA and IDC operate under existing enabling legislation (IDC Act 22 of 1940, SEFA subsidiary mandate). International concessional loans require National Treasury approval and a PFMA section 66 guarantee if sovereign guarantee is needed. JET Presidential Climate Commission operates under the Climate Change Act 22 of 2024 and Presidential resolution. Local content requirements for JET projects require dtic designation under the IPAP and existing manufacturing development regulations.',
    'JET-SMME Facility is within SEFA and IDC''s existing statutory mandates — board resolutions required, not legislation. International partner concessional finance agreements are executive instruments through National Treasury and DIRCO. Climate Change Act 22 of 2024 provides the policy framework for JET. Presidential Climate Commission recommendations are advisory to Cabinet — implementation through IDC, SEFA, and DSBD administrative decisions.',
    'The JET-IP has broad international support and domestic support among renewable energy developers, labour (NUMSA has shifted to conditional JET acceptance), and climate civil society. The SMME-inclusive framing addresses the political tension within COSATU between climate action and coal worker job losses. National Treasury and IDC are aligned on blended finance. GNU parties support JET: DA (economic growth), ANC (transformation and coal community obligations), IFP (KZN green economy). The coal community programme is the critical political variable — Mpumalanga ANC structures require demonstrable local economic benefits.',
    'South Africa''s own JET-IP is a global reference case; the SMME facility adds the inclusive finance dimension that has been missing. Germany''s KfW Green SME programme (KfW Klimaschutzoffensive für den Mittelstand) provides a direct model — concessional finance for SME energy transition. EU''s ELENA (European Local ENergy Assistance) technical assistance facility for small clean energy projects is the model for the GIZ technical assistance component. Kenya''s M-KOPA solar financing (SMME distribution model) demonstrates how SMME supply chains can drive residential solar adoption at scale. Morocco''s NOOR solar programme local content requirements created 15,000 SMME jobs — the supply chain localisation model SA should replicate.'
);

COMMIT;
